{
  "name": "TravelGenius AI",
  "description": "An intelligent, drag-and-drop travel itinerary planner powered by Gemini. Features automatic schedule generation, daily customization, and a beautiful visual overview."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TravelStyle {
  RELAXED = 'Relaxed',
  FOODIE = 'Foodie',
  ADVENTURE = 'Adventure',
  ARTSY = 'Artsy/Cultural',
  SCENIC = 'Scenic',
  SIGHTSEEING = 'Sightseeing',
  SHOPPING = 'Shopping',
  FAMILY = 'Family',
}

export interface TripData {
  destination: string;
  arrivalDate: string;
  arrivalTime: string;
  departureDate: string;
  departureTime: string;
  adults: number;
  children: number;
  accommodation: string;
  dailyAccommodations: Record<number, string>; // Day index -> Address
  breakfastTime: string;
  selfDrive: boolean;
  styles: TravelStyle[];
  mustSees: string;
}

export interface Activity {
  id: string;
  dayIndex: number;
  startTime: string; // HH:MM
  durationMinutes: number;
  title: string;
  description: string;
  location: string;
  type: 'food' | 'sight' | 'shopping' | 'transport' | 'other';
  rating: number; // 1-5 stars (User set)
  tips?: string;
  transportInfo?: string;
  reason?: string;
  imageUrl?: string; // Placeholder or generated
  isLocked?: boolean; // If 5 stars, treated as locked during regeneration
}

export type Itinerary = Activity[];

export interface AppState {
  step: 'context' | 'planner' | 'overview';
  tripData: TripData;
  itinerary: Itinerary;
  isLoading: boolean;
  loadingMessage: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripData, Activity, Itinerary } from "../types";
import { v4 as uuidv4 } from 'uuid';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Common schema definitions
const activitySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    startTime: { type: Type.STRING, description: "Start time in HH:MM format (24h)" },
    durationMinutes: { type: Type.INTEGER, description: "Duration in minutes" },
    title: { type: Type.STRING },
    description: { type: Type.STRING, description: "Short description of the activity" },
    location: { type: Type.STRING, description: "Address or Place Name" },
    type: { type: Type.STRING, enum: ["food", "sight", "shopping", "transport", "other"] },
    tips: { type: Type.STRING, description: "Important tips or warnings" },
    transportInfo: { type: Type.STRING, description: "How to get there from previous location or accommodation" },
    reason: { type: Type.STRING, description: "Why this was recommended based on user preferences" },
  },
  required: ["startTime", "durationMinutes", "title", "description", "location", "type", "transportInfo"],
};

const daySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    dayIndex: { type: Type.INTEGER },
    activities: {
      type: Type.ARRAY,
      items: activitySchema,
    },
  },
  required: ["dayIndex", "activities"],
};

const itinerarySchema: Schema = {
  type: Type.ARRAY,
  items: daySchema,
};

export const generateInitialItinerary = async (tripData: TripData): Promise<Itinerary> => {
  const ai = getAiClient();

  const daysCount = calculateDays(tripData.arrivalDate, tripData.departureDate);

  const prompt = `
    Create a detailed travel itinerary for a trip to ${tripData.destination}.

    Context:
    - Arrival: ${tripData.arrivalDate} at ${tripData.arrivalTime}
    - Departure: ${tripData.departureDate} at ${tripData.departureTime}
    - Party: ${tripData.adults} Adults, ${tripData.children} Children
    - Main Accommodation: ${tripData.accommodation}
    - Breakfast Time: ${tripData.breakfastTime}
    - Driving: ${tripData.selfDrive ? "Yes" : "No"}
    - Styles: ${tripData.styles.join(", ")}
    - Must See: ${tripData.mustSees}

    Requirements:
    - Plan for ${daysCount} days.
    - Day 1 starts after arrival time. Last day ends before departure time.
    - Include Breakfast, Lunch, and Dinner suggestions each day (unless flying).
    - Start daily itinerary 30 mins after breakfast time.
    - Consider the specific accommodation location for logistics.
    - Be logical with geography to minimize travel time.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        systemInstruction: "You are an expert travel planner. Return JSON only.",
      },
    });

    const rawData = JSON.parse(response.text || "[]");
    return parseGeminiResponseToItinerary(rawData);

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

export const regenerateActivity = async (
  tripData: TripData, 
  currentActivity: Activity, 
  dayActivities: Activity[],
  promptOverride?: string
): Promise<Activity> => {
  const ai = getAiClient();

  const prompt = `
    Regenerate a single activity for a trip to ${tripData.destination}.
    Existing Activity to Replace: ${currentActivity.title} (${currentActivity.startTime}).

    Context of the day (other activities): ${dayActivities.map(a => `${a.startTime}: ${a.title}`).join(", ")}.
    Accommodation that day: ${tripData.dailyAccommodations[currentActivity.dayIndex] || tripData.accommodation}.

    ${promptOverride ? `User Specific Request: ${promptOverride}` : "Suggestion: Provide a different alternative that fits the time slot and location flow. Don't repeat existing activities."}

    Return a single activity object.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: activitySchema,
    },
  });

  const rawActivity = JSON.parse(response.text || "{}");
  return {
    ...currentActivity,
    ...rawActivity,
    id: uuidv4(), // New ID for the new item
    rating: 0, // Reset rating
  };
};

export const regenerateDay = async (
  tripData: TripData,
  dayIndex: number,
  currentActivities: Activity[]
): Promise<Activity[]> => {
  const ai = getAiClient();

  // Filter out locked (5-star) activities
  const lockedActivities = currentActivities.filter(a => a.rating === 5);

  const prompt = `
    Regenerate the itinerary for Day ${dayIndex + 1} in ${tripData.destination}.
    Accommodation: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}.
    Breakfast: ${tripData.breakfastTime}.

    Constraints:
    - KEEP these locked activities at their specific times: ${JSON.stringify(lockedActivities.map(a => ({ time: a.startTime, title: a.title })))}.
    - Fill the rest of the day around them.
    - Ensure logical flow.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: daySchema,
    },
  });

  const rawData = JSON.parse(response.text || "{}");

  // Merge result: prefer locked existing items if returned, or strictly inject them back
  const newActivities = (rawData.activities || []).map((raw: any) => ({
    id: uuidv4(),
    dayIndex: dayIndex,
    startTime: raw.startTime,
    durationMinutes: raw.durationMinutes,
    title: raw.title,
    description: raw.description,
    location: raw.location,
    type: raw.type,
    rating: 0,
    tips: raw.tips,
    transportInfo: raw.transportInfo,
    reason: raw.reason,
    imageUrl: `https://picsum.photos/seed/${encodeURIComponent(raw.title)}/400/300`,
  }));

  // Simple merge strategy: If a locked activity exists, ensure it is present. 
  // For simplicity in this demo, we replace the whole day list but ideally we would weave them.
  // Since the prompt explicitly asked to keep them, we assume the AI respected the time slots.
  // We will force-overwrite any slot that overlaps a locked item with the locked item data.

  let merged = [...newActivities];
  lockedActivities.forEach(locked => {
    // Remove conflicting generated items
    merged = merged.filter(a => a.startTime !== locked.startTime);
    merged.push(locked);
  });

  return merged.sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const suggestGapActivity = async (
  tripData: TripData,
  dayIndex: number,
  startTime: string,
  availableMinutes: number
): Promise<Activity> => {
    const ai = getAiClient();
    const prompt = `
        Suggest a short activity for a gap in the schedule.
        Location: ${tripData.destination}.
        Day: ${dayIndex + 1}.
        Start Time: ${startTime}.
        Available Duration: ${availableMinutes} minutes.
        Accommodation: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}.
        Style: ${tripData.styles.join(', ')}.
        Constraint: Must be feasible in the time/location. e.g., "Coffee break", "Quick walk", "Souvenir shop".
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: activitySchema,
        }
    });

    const raw = JSON.parse(response.text || "{}");
    return {
        id: uuidv4(),
        dayIndex,
        startTime: raw.startTime || startTime, // Ensure it respects requested time
        durationMinutes: Math.min(raw.durationMinutes, availableMinutes),
        title: raw.title,
        description: raw.description,
        location: raw.location,
        type: raw.type,
        rating: 0,
        tips: raw.tips,
        transportInfo: raw.transportInfo,
        reason: raw.reason,
        imageUrl: `https://picsum.photos/seed/${encodeURIComponent(raw.title)}/400/300`,
    };
}


// Utilities

function calculateDays(start: string, end: string) {
  if (!start || !end) return 1;
  const d1 = new Date(start);
  const d2 = new Date(end);
  const diffTime = Math.abs(d2.getTime() - d1.getTime());
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 
}

function parseGeminiResponseToItinerary(data: any[]): Itinerary {
  const itinerary: Itinerary = [];

  data.forEach((day: any) => {
    if (day.activities && Array.isArray(day.activities)) {
      day.activities.forEach((act: any) => {
        itinerary.push({
          id: uuidv4(),
          dayIndex: day.dayIndex !== undefined ? day.dayIndex - 1 : 0, // Gemini might return 1-based
          startTime: act.startTime,
          durationMinutes: act.durationMinutes,
          title: act.title,
          description: act.description,
          location: act.location,
          type: act.type,
          rating: 0,
          tips: act.tips,
          transportInfo: act.transportInfo,
          reason: act.reason,
          imageUrl: `https://picsum.photos/seed/${encodeURIComponent(act.title)}/400/300`,
        });
      });
    }
  });

  return itinerary;
}

import React from 'react';
import { Loader2 } from 'lucide-react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-primary text-white hover:bg-sky-600 focus:ring-primary",
    secondary: "bg-white text-slate-700 border border-slate-300 hover:bg-slate-50 focus:ring-slate-500",
    danger: "bg-red-500 text-white hover:bg-red-600 focus:ring-red-500",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 focus:ring-slate-400",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
      {children}
    </button>
  );
};

