import React, { useEffect, useState } from 'react';
import { TripData, TravelStyle } from '../types';
import { Button } from '../components/Button';
import { Calendar, Clock, MapPin, Users, Home, Coffee, Car } from 'lucide-react';
import { differenceInCalendarDays } from 'date-fns';

interface TripContextProps {
  initialData: TripData;
  onComplete: (data: TripData) => void;
  isGenerating: boolean;
}

export const TripContext: React.FC<TripContextProps> = ({ initialData, onComplete, isGenerating }) => {
  const [formData, setFormData] = useState<TripData>(initialData);
  const [duration, setDuration] = useState({ days: 0, nights: 0 });

  useEffect(() => {
    if (formData.arrivalDate && formData.departureDate) {
      const start = new Date(formData.arrivalDate);
      const end = new Date(formData.departureDate);
      const days = differenceInCalendarDays(end, start) + 1;
      const nights = days - 1 > 0 ? days - 1 : 0;
      setDuration({ days: days > 0 ? days : 0, nights });
    }
  }, [formData.arrivalDate, formData.departureDate]);

  const handleArrivalDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newArrival = e.target.value;
    // Auto set departure to next day
    const nextDay = new Date(newArrival);
    nextDay.setDate(nextDay.getDate() + 1);
    const nextDayStr = nextDay.toISOString().split('T')[0];

    setFormData(prev => ({
      ...prev,
      arrivalDate: newArrival,
      departureDate: prev.departureDate < newArrival ? nextDayStr : prev.departureDate
    }));
  };

  const toggleStyle = (style: TravelStyle) => {
    setFormData(prev => {
      const styles = prev.styles.includes(style)
        ? prev.styles.filter(s => s !== style)
        : [...prev.styles, style];
      return { ...prev, styles };
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onComplete(formData);
  };

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8">
        <h1 className="text-3xl font-bold text-slate-900 mb-6 flex items-center gap-2">
          <MapPin className="text-primary" />
          Plan Your Trip
        </h1>

        <form onSubmit={handleSubmit} className="space-y-8">
          {/* Destination & Duration */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="block text-sm font-medium text-slate-700">Country / City</label>
              <input
                type="text"
                required
                className="w-full rounded-lg border-slate-300 shadow-sm focus:border-primary focus:ring-primary p-2 border"
                value={formData.destination}
                onChange={e => setFormData({ ...formData, destination: e.target.value })}
                placeholder="e.g. Tokyo, Japan"
              />
            </div>

            <div className="bg-blue-50 p-4 rounded-lg flex items-center justify-center text-blue-800 font-medium">
              {duration.days > 0 ? (
                <span>Trip Duration: {duration.days} Days / {duration.nights} Nights</span>
              ) : (
                <span className="text-blue-400">Select dates to calculate duration</span>
              )}
            </div>
          </div>

          {/* Dates & Times */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-medium text-slate-500">Arrival Date</label>
              <input type="date" required className="w-full p-2 border rounded-md" 
                value={formData.arrivalDate} onChange={handleArrivalDateChange} />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-medium text-slate-500">Time</label>
              <input type="time" required className="w-full p-2 border rounded-md" 
                value={formData.arrivalTime} onChange={e => setFormData({ ...formData, arrivalTime: e.target.value })} />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-medium text-slate-500">Departure Date</label>
              <input type="date" required className="w-full p-2 border rounded-md" 
                min={formData.arrivalDate}
                value={formData.departureDate} onChange={e => setFormData({ ...formData, departureDate: e.target.value })} />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-medium text-slate-500">Time</label>
              <input type="time" required className="w-full p-2 border rounded-md" 
                value={formData.departureTime} onChange={e => setFormData({ ...formData, departureTime: e.target.value })} />
            </div>
          </div>

          {/* Party & Accommodation */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="flex gap-4">
                <div className="flex-1">
                    <label className="block text-sm font-medium text-slate-700 mb-1">Adults</label>
                    <div className="relative">
                        <Users className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                        <input type="number" min="1" className="w-full pl-10 p-2 border rounded-md"
                            value={formData.adults} onChange={e => setFormData({...formData, adults: parseInt(e.target.value)})} />
                    </div>
                </div>
                <div className="flex-1">
                    <label className="block text-sm font-medium text-slate-700 mb-1">Children</label>
                    <input type="number" min="0" className="w-full p-2 border rounded-md"
                        value={formData.children} onChange={e => setFormData({...formData, children: parseInt(e.target.value)})} />
                </div>
             </div>

             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Accommodation (Default)</label>
                <div className="relative">
                    <Home className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                    <input type="text" className="w-full pl-10 p-2 border rounded-md"
                        placeholder="Hotel Name or Area"
                        value={formData.accommodation} onChange={e => setFormData({...formData, accommodation: e.target.value})} />
                </div>
             </div>
          </div>

          {/* Preferences */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Breakfast Time</label>
                <div className="relative">
                    <Coffee className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                    <input type="time" className="w-full pl-10 p-2 border rounded-md"
                        value={formData.breakfastTime} onChange={e => setFormData({...formData, breakfastTime: e.target.value})} />
                </div>
             </div>

             <div className="flex items-center gap-3">
                <div className={`p-3 rounded-full cursor-pointer transition-colors ${formData.selfDrive ? 'bg-primary text-white' : 'bg-slate-100 text-slate-400'}`}
                     onClick={() => setFormData({...formData, selfDrive: !formData.selfDrive})}>
                    <Car className="w-6 h-6" />
                </div>
                <span className="text-sm font-medium text-slate-700">Self Drive? {formData.selfDrive ? 'Yes' : 'No'}</span>
             </div>
          </div>

          {/* Styles */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-3">Travel Style</label>
            <div className="flex flex-wrap gap-2">
                {Object.values(TravelStyle).map(style => (
                    <button
                        key={style}
                        type="button"
                        onClick={() => toggleStyle(style)}
                        className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                            formData.styles.includes(style)
                            ? 'bg-primary text-white shadow-md transform scale-105'
                            : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'
                        }`}
                    >
                        {style}
                    </button>
                ))}
            </div>
          </div>

          {/* Must See */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Must-See Attractions (Optional)</label>
            <textarea 
                className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent"
                rows={3}
                placeholder="List specific places you want to visit..."
                value={formData.mustSees}
                onChange={e => setFormData({...formData, mustSees: e.target.value})}
            />
          </div>

          <div className="pt-4 flex justify-end">
            <Button type="submit" size="lg" className="w-full md:w-auto text-lg px-8 py-3" isLoading={isGenerating}>
              {isGenerating ? 'Designing Your Journey...' : 'Generate Itinerary'}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { TripData, Itinerary, Activity } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { MapPin, Clock, Star, RefreshCw, X, Edit, Info, Plus } from 'lucide-react';
import { format, addDays, parseISO } from 'date-fns';

interface ItineraryPlannerProps {
  tripData: TripData;
  itinerary: Itinerary;
  onUpdateItinerary: (newItinerary: Itinerary) => void;
  onUpdateTripData: (newData: TripData) => void;
  onRegenerateItem: (item: Activity, prompt?: string) => Promise<void>;
  onRegenerateDay: (dayIndex: number) => Promise<void>;
  onAddItem: (dayIndex: number, time: string) => Promise<void>;
}

export const ItineraryPlanner: React.FC<ItineraryPlannerProps> = ({
  tripData,
  itinerary,
  onUpdateItinerary,
  onUpdateTripData,
  onRegenerateItem,
  onRegenerateDay,
  onAddItem
}) => {
  const [selectedActivity, setSelectedActivity] = useState<Activity | null>(null);
  const [draggedActivity, setDraggedActivity] = useState<Activity | null>(null);
  const [isRegenerating, setIsRegenerating] = useState<string | null>(null); // ID or 'day-X'
  const [promptMode, setPromptMode] = useState(false);
  const [customPrompt, setCustomPrompt] = useState('');

  const days = Array.from({ length: differenceInDays(tripData.arrivalDate, tripData.departureDate) }, (_, i) => i);
  const hours = Array.from({ length: 16 }, (_, i) => i + 7); // 7 AM to 10 PM

  // --- Drag & Drop Logic (HTML5) ---
  const handleDragStart = (e: React.DragEvent, activity: Activity) => {
    setDraggedActivity(activity);
    e.dataTransfer.effectAllowed = 'move';
    // Transparent drag image usually preferred or default
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetDayIndex: number, targetTime: string) => {
    e.preventDefault();
    if (!draggedActivity) return;

    const newItinerary = [...itinerary];
    const activityIndex = newItinerary.findIndex(a => a.id === draggedActivity.id);

    if (activityIndex > -1) {
      newItinerary[activityIndex] = {
        ...draggedActivity,
        dayIndex: targetDayIndex,
        startTime: targetTime,
      };

      // Sort items for that day
      onUpdateItinerary(newItinerary.sort((a, b) => a.startTime.localeCompare(b.startTime)));
    }
    setDraggedActivity(null);
  };

  // --- Helpers ---
  const getActivitiesForDay = (dayIndex: number) => {
    return itinerary.filter(a => a.dayIndex === dayIndex).sort((a, b) => a.startTime.localeCompare(b.startTime));
  };

  const toggleStar = (e: React.MouseEvent, id: string, current: number) => {
    e.stopPropagation();
    const newRating = current === 5 ? 0 : 5;
    const newItinerary = itinerary.map(a => a.id === id ? { ...a, rating: newRating } : a);
    onUpdateItinerary(newItinerary);
  };

  const handleDelete = (id: string) => {
    onUpdateItinerary(itinerary.filter(a => a.id !== id));
    setSelectedActivity(null);
  };

  const handleRegenerateClick = async (item: Activity) => {
    setIsRegenerating(item.id);
    await onRegenerateItem(item, promptMode ? customPrompt : undefined);
    setIsRegenerating(null);
    setPromptMode(false);
    setCustomPrompt('');
    setSelectedActivity(null);
  };

  const handleRegenerateDayClick = async (dayIndex: number) => {
    if (window.confirm("Regenerate this whole day? 5-star items will be kept.")) {
        setIsRegenerating(`day-${dayIndex}`);
        await onRegenerateDay(dayIndex);
        setIsRegenerating(null);
    }
  };

  const handleAccommodationChange = (dayIndex: number, val: string) => {
    onUpdateTripData({
        ...tripData,
        dailyAccommodations: {
            ...tripData.dailyAccommodations,
            [dayIndex]: val
        }
    });
  };

  return (
    <div className="h-full flex flex-col overflow-hidden bg-slate-50">
      {/* Header Grid */}
      <div className="flex-none overflow-x-auto border-b border-slate-200 bg-white shadow-sm z-10">
         <div className="flex min-w-max">
            <div className="w-20 flex-none bg-slate-100 border-r border-slate-200 p-4 font-bold text-slate-400 flex items-center justify-center">
                Time
            </div>
            {days.map(dayIndex => {
                const date = addDays(parseISO(tripData.arrivalDate), dayIndex);
                return (
                    <div key={dayIndex} className="w-80 flex-none border-r border-slate-200 p-4">
                        <div className="flex justify-between items-start mb-2">
                            <div>
                                <h3 className="font-bold text-slate-800">Day {dayIndex + 1}</h3>
                                <p className="text-sm text-slate-500">{format(date, 'MMM dd, yyyy')}</p>
                            </div>
                            <button 
                                onClick={() => handleRegenerateDayClick(dayIndex)}
                                disabled={!!isRegenerating}
                                className="p-1.5 hover:bg-slate-100 rounded text-primary"
                                title="Regenerate Day"
                            >
                                <RefreshCw className={`w-4 h-4 ${isRegenerating === `day-${dayIndex}` ? 'animate-spin' : ''}`} />
                            </button>
                        </div>

                        {/* Accommodation Input */}
                        <div className="flex items-center gap-2 text-xs text-slate-600 bg-slate-50 p-2 rounded">
                            <HomeIcon className="w-3 h-3" />
                            <input 
                                className="bg-transparent border-none p-0 w-full focus:ring-0 text-xs truncate"
                                value={tripData.dailyAccommodations[dayIndex] || tripData.accommodation}
                                onChange={(e) => handleAccommodationChange(dayIndex, e.target.value)}
                                placeholder="Stay location..."
                            />
                        </div>
                    </div>
                );
            })}
         </div>
      </div>

      {/* Main Grid Scrollable Area */}
      <div className="flex-1 overflow-auto">
        <div className="flex min-w-max relative">
            {/* Time Column */}
            <div className="w-20 flex-none bg-slate-50 border-r border-slate-200">
                {hours.map(h => (
                    <div key={h} className="h-48 border-b border-slate-200 p-2 text-xs font-medium text-slate-400 text-center sticky left-0">
                        {h}:00
                    </div>
                ))}
            </div>

            {/* Day Columns */}
            {days.map(dayIndex => {
                const dayActivities = getActivitiesForDay(dayIndex);
                return (
                    <div key={dayIndex} className="w-80 flex-none border-r border-slate-200 relative bg-white">
                        {hours.map(hour => {
                            const timeStr = `${hour.toString().padStart(2, '0')}:00`;
                            const activitiesInSlot = dayActivities.filter(a => {
                                const activityHour = parseInt(a.startTime.split(':')[0]);
                                return activityHour === hour;
                            });

                            return (
                                <div 
                                    key={hour} 
                                    className="h-48 border-b border-slate-100 p-2 relative group"
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, dayIndex, timeStr)}
                                >
                                    {/* Empty Slot Add Button */}
                                    {activitiesInSlot.length === 0 && (
                                        <button 
                                            onClick={() => onAddItem(dayIndex, timeStr)}
                                            className="absolute inset-0 m-auto w-8 h-8 rounded-full bg-slate-50 border border-slate-200 text-slate-400 opacity-0 group-hover:opacity-100 flex items-center justify-center hover:bg-primary hover:text-white transition-all z-0"
                                            title="Add Activity"
                                        >
                                            <Plus className="w-4 h-4" />
                                        </button>
                                    )}

                                    {activitiesInSlot.map(activity => (
                                        <div
                                            key={activity.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, activity)}
                                            onClick={() => setSelectedActivity(activity)}
                                            className={`relative z-10 mb-2 p-2 rounded-lg border shadow-sm cursor-pointer transition-all hover:shadow-md hover:scale-[1.02] bg-white group/card
                                                ${activity.type === 'food' ? 'border-orange-200 bg-orange-50' : 
                                                  activity.type === 'sight' ? 'border-sky-200 bg-sky-50' : 'border-slate-200'}
                                            `}
                                        >
                                            <div className="flex gap-2">
                                                <img src={activity.imageUrl} alt="" className="w-12 h-12 rounded object-cover bg-slate-200 flex-none" />
                                                <div className="overflow-hidden">
                                                    <div className="flex justify-between items-start">
                                                        <span className="text-xs font-bold text-slate-500">{activity.startTime}</span>
                                                        <div className="flex gap-1">
                                                            <button 
                                                                onClick={(e) => { e.stopPropagation(); setIsRegenerating(activity.id); onRegenerateItem(activity); }}
                                                                className={`p-1 hover:bg-black/10 rounded-full ${isRegenerating === activity.id ? 'animate-spin' : ''}`}>
                                                                <RefreshCw className="w-3 h-3 text-slate-500" />
                                                            </button>
                                                            <button 
                                                                onClick={(e) => toggleStar(e, activity.id, activity.rating)}
                                                                className="p-1 hover:bg-black/10 rounded-full">
                                                                <Star className={`w-3 h-3 ${activity.rating === 5 ? 'fill-yellow-400 text-yellow-400' : 'text-slate-300'}`} />
                                                            </button>
                                                        </div>
                                                    </div>
                                                    <h4 className="text-sm font-semibold truncate leading-tight">{activity.title}</h4>
                                                    <p className="text-xs text-slate-500 truncate">{activity.durationMinutes} min</p>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            );
                        })}
                    </div>
                );
            })}
        </div>
      </div>

      {/* Activity Details Modal */}
      <Modal
        isOpen={!!selectedActivity}
        onClose={() => { setSelectedActivity(null); setPromptMode(false); }}
        title={selectedActivity?.title || ''}
        footer={
            <>
                <Button variant="danger" onClick={() => selectedActivity && handleDelete(selectedActivity.id)}>Delete</Button>
                <div className="flex-1"></div>
                {promptMode ? (
                     <div className="flex w-full gap-2">
