import React, { useState } from 'react';
import { TripData, Itinerary, Activity, TravelStyle } from './types';
import { TripContext } from './views/TripContext';
import { ItineraryPlanner } from './views/ItineraryPlanner';
import { ItineraryOverview } from './views/ItineraryOverview';
import { generateInitialItinerary, regenerateActivity, regenerateDay, suggestGapActivity } from './services/geminiService';
import { LayoutGrid, Calendar, Map } from 'lucide-react';

const INITIAL_TRIP_DATA: TripData = {
  destination: '',
  arrivalDate: '',
  arrivalTime: '10:00',
  departureDate: '',
  departureTime: '18:00',
  adults: 2,
  children: 0,
  accommodation: '',
  dailyAccommodations: {},
  breakfastTime: '08:00',
  selfDrive: false,
  styles: [],
  mustSees: '',
};

const App: React.FC = () => {
  const [step, setStep] = useState<'context' | 'planner' | 'overview'>('context');
  const [tripData, setTripData] = useState<TripData>(INITIAL_TRIP_DATA);
  const [itinerary, setItinerary] = useState<Itinerary>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleTripContextComplete = async (data: TripData) => {
    setTripData(data);
    setIsGenerating(true);
    setError(null);
    try {
      const generatedItinerary = await generateInitialItinerary(data);
      setItinerary(generatedItinerary);
      setStep('planner');
    } catch (e) {
      console.error(e);
      setError("Failed to generate itinerary. Please check your API key and try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRegenerateItem = async (item: Activity, promptOverride?: string) => {
    try {
      const dayActivities = itinerary.filter(a => a.dayIndex === item.dayIndex && a.id !== item.id);
      const newItem = await regenerateActivity(tripData, item, dayActivities, promptOverride);
      setItinerary(prev => prev.map(a => a.id === item.id ? newItem : a));
    } catch (e) {
      console.error(e);
      alert("Failed to regenerate activity.");
    }
  };

  const handleRegenerateDay = async (dayIndex: number) => {
    try {
      const currentDayActivities = itinerary.filter(a => a.dayIndex === dayIndex);
      const newDayActivities = await regenerateDay(tripData, dayIndex, currentDayActivities);

      // Remove old day activities and add new ones
      setItinerary(prev => [
        ...prev.filter(a => a.dayIndex !== dayIndex),
        ...newDayActivities
      ]);
    } catch (e) {
      console.error(e);
      alert("Failed to regenerate day.");
    }
  };

  const handleAddItem = async (dayIndex: number, time: string) => {
    // Basic logic: find gap or just add 60 min item
    try {
        const newItem = await suggestGapActivity(tripData, dayIndex, time, 60);
        setItinerary(prev => [...prev, newItem].sort((a,b) => a.startTime.localeCompare(b.startTime)));
    } catch(e) {
        console.error(e);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      {/* Top Navigation Bar (Visible only after initial setup) */}
      {step !== 'context' && (
        <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
            <div className="font-bold text-xl text-primary flex items-center gap-2">
                <Map className="w-6 h-6"/> TravelGenius
            </div>
            <div className="flex bg-slate-100 rounded-lg p-1">
              <button 
                onClick={() => setStep('planner')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-colors ${step === 'planner' ? 'bg-white shadow text-primary' : 'text-slate-500 hover:text-slate-900'}`}
              >
                <LayoutGrid className="w-4 h-4" /> Details
              </button>
              <button 
                onClick={() => setStep('overview')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-colors ${step === 'overview' ? 'bg-white shadow text-primary' : 'text-slate-500 hover:text-slate-900'}`}
              >
                <Calendar className="w-4 h-4" /> Overview
              </button>
            </div>
            <button onClick={() => setStep('context')} className="text-sm text-slate-500 hover:text-primary underline">
                Edit Context
            </button>
          </div>
        </header>
      )}

      {/* Main Content */}
      <main className="flex-1 relative">
        {error && (
            <div className="absolute top-4 left-1/2 transform -translate-x-1/2 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded z-50">
                {error}
            </div>
        )}

        {step === 'context' && (
          <TripContext 
            initialData={tripData} 
            onComplete={handleTripContextComplete} 
            isGenerating={isGenerating} 
          />
        )}

        {step === 'planner' && (
          <ItineraryPlanner 
            tripData={tripData}
            itinerary={itinerary}
            onUpdateItinerary={setItinerary}
            onUpdateTripData={setTripData}
            onRegenerateItem={handleRegenerateItem}
            onRegenerateDay={handleRegenerateDay}
            onAddItem={handleAddItem}
          />
        )}

        {step === 'overview' && (
            <ItineraryOverview tripData={tripData} itinerary={itinerary} />
        )}
      </main>
    </div>
  );
};

export default App;

