        }
      >
        {selectedActivity && (
            <div className="space-y-5">
                <div className="relative rounded-2xl overflow-hidden shadow-lg h-56 group">
                    <img src={selectedActivity.imageUrl} className="w-full h-full object-cover" alt={selectedActivity.title} />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent"></div>
                    <div className="absolute bottom-4 left-4 text-white">
                        <div className="flex items-center gap-2 text-sm font-medium mb-1 opacity-90">
