                        <h2 className="text-2xl font-bold tracking-tight">{selectedActivity.title}</h2>
                    </div>
                    <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md p-1.5 rounded-lg cursor-pointer hover:bg-white/30 transition-colors"
