                         {[1,2,3,4,5].map(star => (
                             <Star key={star} className={`w-5 h-5 inline-block ${star <= selectedActivity.rating ? 'fill-yellow-400 text-yellow-400' : 'text-white/50'}`} />
                         ))}
                    </div>
                </div>

                <div className="space-y-4">
                    <p className="text-slate-700 text-lg leading-relaxed font-medium">{selectedActivity.description}</p>

