                            <MapPin className="w-5 h-5 text-primary mt-0.5 flex-none" />
                            <div>
                                <h5 className="font-bold text-slate-900 text-sm">詳細地址</h5>
                                <p className="text-slate-600 text-sm">{selectedActivity.location}</p>
                            </div>
                         </div>

                         <div className="bg-accent/5 p-4 rounded-xl border border-accent/20">
                            <h5 className="font-bold text-accent text-sm mb-2 flex items-center gap-2"><Star className="w-4 h-4" /> 推介原因</h5>
                            <p className="text-slate-700 text-sm italic">“{selectedActivity.reason}”</p>
                         </div>

                        {(selectedActivity.tips || selectedActivity.transportInfo) && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {selectedActivity.tips && (
                                    <div className="bg-orange-50 p-4 rounded-xl border border-orange-100">
                                        <h5 className="font-bold text-orange-600 text-sm mb-1">注意事項</h5>
                                        <p className="text-slate-600 text-xs">{selectedActivity.tips}</p>
                                    </div>
                                )}
                                {selectedActivity.transportInfo && (
                                    <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
                                        <h5 className="font-bold text-blue-600 text-sm mb-1">交通建議</h5>
                                        <p className="text-slate-600 text-xs">{selectedActivity.transportInfo}</p>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        )}
      </Modal>
    </div>
  );
};

function differenceInDays(start: string, end: string) {
    if(!start || !end) return 1;
    const d1 = new Date(start);
    const d2 = new Date(end);
    return Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24)) + 1;
}

function addMinutes(time: string, minutes: number): string {
    const [h, m] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m + minutes);
    return format(date, 'HH:mm');
}

