import React, { useState } from 'react';
import { TripData, Itinerary, Activity } from './types';
import { TripContext } from './views/TripContext';
import { ItineraryPlanner } from './views/ItineraryPlanner';
import { ItineraryOverview } from './views/ItineraryOverview';
import { generateInitialItinerary, regenerateActivity, regenerateDay, suggestGapActivity } from './services/geminiService';
import { LayoutGrid, Calendar, ArrowLeft } from 'lucide-react';
import { Logo } from './components/Logo';

const INITIAL_TRIP_DATA: TripData = {
  destination: '',
  arrivalDate: '',
  arrivalTime: '10:00',
  departureDate: '',
  departureTime: '18:00',
  adults: 2, // Default updated
  children: 1, // Default updated
  accommodation: '',
  dailyAccommodations: {},
  breakfastTime: '09:00',
  selfDrive: false,
  styles: [],
  mustSees: '',
};

const App: React.FC = () => {
  const [step, setStep] = useState<'context' | 'planner' | 'overview'>('context');
  const [tripData, setTripData] = useState<TripData>(INITIAL_TRIP_DATA);
  const [itinerary, setItinerary] = useState<Itinerary>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleTripContextComplete = async (data: TripData) => {
    setTripData(data);
    setIsGenerating(true);
    setError(null);
    try {
      const generatedItinerary = await generateInitialItinerary(data);
      setItinerary(generatedItinerary);
      setStep('planner');
    } catch (e) {
      console.error(e);
      setError("無法生成行程，請檢查 API Key 或網絡連接。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRegenerateItem = async (item: Activity, promptOverride?: string) => {
    try {
      const dayActivities = itinerary.filter(a => a.dayIndex === item.dayIndex && a.id !== item.id);
      const newItem = await regenerateActivity(tripData, item, dayActivities, promptOverride);
      setItinerary(prev => prev.map(a => a.id === item.id ? newItem : a));
    } catch (e) {
      console.error(e);
      alert("更新失敗，請稍後再試。");
    }
  };

  const handleRegenerateDay = async (dayIndex: number) => {
    try {
      const currentDayActivities = itinerary.filter(a => a.dayIndex === dayIndex);
      const newDayActivities = await regenerateDay(tripData, dayIndex, currentDayActivities);

      setItinerary(prev => [
        ...prev.filter(a => a.dayIndex !== dayIndex),
        ...newDayActivities
      ]);
    } catch (e) {
      console.error(e);
      alert("更新全日行程失敗。");
    }
  };

  const handleAddItem = async (dayIndex: number, time: string) => {
    try {
        const newItem = await suggestGapActivity(tripData, dayIndex, time, 60);
        setItinerary(prev => [...prev, newItem].sort((a,b) => a.startTime.localeCompare(b.startTime)));
    } catch(e) {
        console.error(e);
    }
  };

  const handleMoveActivity = async (
    activityId: string, 
    newDayIndex: number, 
    newTime: string,
    oldDayIndex: number,
    oldTime: string,
    duration: number
  ) => {
    // 1. Move the existing activity immediately
    setItinerary(prev => {
        return prev.map(item => {
            if (item.id === activityId) {
                return { ...item, dayIndex: newDayIndex, startTime: newTime };
            }
            return item;
        }).sort((a, b) => a.startTime.localeCompare(b.startTime));
    });

    // 2. Automatically fill the old gap
    try {
        // Add a temporary loading placeholder or just wait for result
        const gapActivity = await suggestGapActivity(tripData, oldDayIndex, oldTime, duration);
        setItinerary(prev => [...prev, gapActivity].sort((a, b) => a.startTime.localeCompare(b.startTime)));
    } catch (e) {
        console.error("Failed to auto-fill gap", e);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-background text-slate-900">
      {/* Top Navigation Bar */}
      {step !== 'context' && (
        <header className="bg-white/90 backdrop-blur-xl border-b border-primary/20 sticky top-0 z-50 shadow-sm">
          <div className="max-w-7xl mx-auto px-4 h-18 flex items-center justify-between py-2">
            <div className="flex items-center gap-6">
                <div className="hover:scale-105 transition-transform cursor-pointer" onClick={() => setStep('context')}>
                  <Logo />
                </div>
                <div className="hidden md:flex items-center gap-2 text-sm text-slate-500 border-l-2 pl-6 border-slate-200">
                     <span className="font-extrabold text-slate-800 text-lg">{tripData.destination}</span>
                     <span className="text-slate-300">•</span>
                     <span className="font-medium bg-slate-100 px-2 py-0.5 rounded-full">{tripData.adults} 大 {tripData.children} 小</span>
                </div>
            </div>

            <div className="flex items-center gap-4">
                <div className="flex bg-slate-100/80 p-1.5 rounded-2xl shadow-inner border border-slate-200">
                <button 
                    onClick={() => setStep('planner')}
                    className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${step === 'planner' ? 'bg-white shadow-md text-primary scale-105 ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-800 hover:bg-white/50'}`}
                >
                    <LayoutGrid className="w-4 h-4" /> 行程細節
                </button>
                <button 
                    onClick={() => setStep('overview')}
                    className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${step === 'overview' ? 'bg-white shadow-md text-primary scale-105 ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-800 hover:bg-white/50'}`}
                >
                    <Calendar className="w-4 h-4" /> 行程概覽
                </button>
                </div>
                <button 
                    onClick={() => setStep('context')} 
                    className="flex items-center gap-1 text-sm font-bold text-slate-400 hover:text-primary transition-colors px-3 py-2 hover:bg-primary/5 rounded-xl"
                    title="修改設定"
                >
                    <ArrowLeft className="w-4 h-4" /> 設定
                </button>
            </div>
          </div>
        </header>
      )}

      {/* Main Content */}
      <main className="flex-1 relative flex flex-col">
        {error && (
            <div className="absolute top-4 left-1/2 transform -translate-x-1/2 bg-red-100 border border-red-400 text-red-700 px-6 py-3 rounded-full shadow-lg z-50 font-bold animate-bounce">
                {error}
            </div>
        )}

        {step === 'context' && (
            <div className="min-h-screen flex flex-col items-center justify-center bg-kiwi-pattern py-10">
                 <div className="mb-8 scale-150 transform hover:rotate-3 transition-transform duration-500">
                     <Logo />
                 </div>
                 <TripContext 
                    initialData={tripData} 
                    onComplete={handleTripContextComplete} 
                    isGenerating={isGenerating} 
                />
            </div>
        )}

        {step === 'planner' && (
          <ItineraryPlanner 
            tripData={tripData}
            itinerary={itinerary}
            onUpdateItinerary={setItinerary}
            onUpdateTripData={setTripData}
            onRegenerateItem={handleRegenerateItem}
            onRegenerateDay={handleRegenerateDay}
            onAddItem={handleAddItem}
            onMoveActivity={handleMoveActivity}
          />
        )}

        {step === 'overview' && (
            <ItineraryOverview tripData={tripData} itinerary={itinerary} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TripData, Itinerary, Activity } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { MapPin, Clock, Star, RefreshCw, X, Edit, Info, Plus, Home, ArrowRight, Trash2, GripVertical } from 'lucide-react';
import { format, addDays, parseISO } from 'date-fns';

interface ItineraryPlannerProps {
  tripData: TripData;
  itinerary: Itinerary;
  onUpdateItinerary: (newItinerary: Itinerary) => void;
  onUpdateTripData: (newData: TripData) => void;
  onRegenerateItem: (item: Activity, prompt?: string) => Promise<void>;
  onRegenerateDay: (dayIndex: number) => Promise<void>;
  onAddItem: (dayIndex: number, time: string) => Promise<void>;
  onMoveActivity: (id: string, newDay: number, newTime: string, oldDay: number, oldTime: string, duration: number) => Promise<void>;
}

export const ItineraryPlanner: React.FC<ItineraryPlannerProps> = ({
  tripData,
  itinerary,
  onUpdateItinerary,
  onUpdateTripData,
  onRegenerateItem,
  onRegenerateDay,
  onAddItem,
  onMoveActivity
}) => {
  const [selectedActivity, setSelectedActivity] = useState<Activity | null>(null);
  const [draggedActivity, setDraggedActivity] = useState<Activity | null>(null);
  const [isRegenerating, setIsRegenerating] = useState<string | null>(null); 
  const [promptMode, setPromptMode] = useState(false);
  const [customPrompt, setCustomPrompt] = useState('');

  const days = Array.from({ length: differenceInDays(tripData.arrivalDate, tripData.departureDate) }, (_, i) => i);
  const hours = Array.from({ length: 16 }, (_, i) => i + 7); // 7 AM to 10 PM

  // --- Drag & Drop Logic (HTML5) ---
  const handleDragStart = (e: React.DragEvent, activity: Activity) => {
    setDraggedActivity(activity);
    e.dataTransfer.effectAllowed = 'move';
    // Make the drag ghost look cleaner
    e.dataTransfer.setData('text/plain', activity.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetDayIndex: number, targetTime: string) => {
    e.preventDefault();
    if (!draggedActivity) return;

    // Call parent to handle logic (move + auto-fill old spot)
    onMoveActivity(
        draggedActivity.id,
        targetDayIndex,
        targetTime,
        draggedActivity.dayIndex,
        draggedActivity.startTime,
        draggedActivity.durationMinutes
    );

    setDraggedActivity(null);
  };

  const getActivitiesForDay = (dayIndex: number) => {
    return itinerary.filter(a => a.dayIndex === dayIndex).sort((a, b) => a.startTime.localeCompare(b.startTime));
  };

  const toggleStar = (e: React.MouseEvent, id: string, current: number) => {
    e.stopPropagation();
    const newRating = current === 5 ? 0 : 5;
    const newItinerary = itinerary.map(a => a.id === id ? { ...a, rating: newRating } : a);
    onUpdateItinerary(newItinerary);
  };

  const handleDelete = (id: string) => {
    onUpdateItinerary(itinerary.filter(a => a.id !== id));
    setSelectedActivity(null);
  };

  const handleTimeChange = (newTime: string) => {
    if (selectedActivity) {
      const updated = { ...selectedActivity, startTime: newTime };
      const newItinerary = itinerary.map(a => a.id === selectedActivity.id ? updated : a)
        .sort((a,b) => a.startTime.localeCompare(b.startTime));
      onUpdateItinerary(newItinerary);
      setSelectedActivity(updated);
    }
  }

  const handleRegenerateClick = async (item: Activity) => {
    setIsRegenerating(item.id);
    await onRegenerateItem(item, promptMode ? customPrompt : undefined);
    setIsRegenerating(null);
    setPromptMode(false);
    setCustomPrompt('');
    setSelectedActivity(null);
  };

  const handleRegenerateDayClick = async (dayIndex: number) => {
    if (window.confirm("重新生成這整天的行程？(已標記 5 星的項目將會保留)")) {
        setIsRegenerating(`day-${dayIndex}`);
        await onRegenerateDay(dayIndex);
        setIsRegenerating(null);
    }
  };

  const handleAccommodationChange = (dayIndex: number, val: string) => {
    onUpdateTripData({
        ...tripData,
        dailyAccommodations: {
            ...tripData.dailyAccommodations,
            [dayIndex]: val
        }
    });
  };

  // Color Mapping for Activity Types
  const getTypeColor = (type: string) => {
    switch (type) {
        case 'food': return 'bg-orange-50/90 border-orange-200 text-orange-800';
        case 'sight': return 'bg-blue-50/90 border-blue-200 text-blue-800';
        case 'shopping': return 'bg-pink-50/90 border-pink-200 text-pink-800';
        case 'transport': return 'bg-slate-100/90 border-slate-300 text-slate-700';
        default: return 'bg-emerald-50/90 border-emerald-200 text-emerald-800';
    }
  };

  return (
    <div className="h-full flex flex-col overflow-hidden bg-kiwi-pattern">
      {/* Header Grid */}
      <div className="flex-none overflow-x-auto border-b-4 border-primary/20 bg-white/95 backdrop-blur shadow-md z-20 scrollbar-hide">
         <div className="flex min-w-max pb-2">
            <div className="w-20 flex-none p-4 flex items-center justify-center font-bold text-slate-400">
                時間
            </div>
            {days.map(dayIndex => {
                const date = addDays(parseISO(tripData.arrivalDate), dayIndex);
                return (
                    <div key={dayIndex} className="w-80 flex-none p-4">
                        <div className="bg-white rounded-2xl border-2 border-primary/10 shadow-lg p-3 relative overflow-hidden group hover:border-primary/40 transition-colors">
                             <div className="absolute top-0 left-0 w-2 h-full bg-gradient-to-b from-primary to-primaryLight"></div>
                             <div className="flex justify-between items-start pl-3">
                                <div>
                                    <h3 className="font-black text-slate-800 text-xl tracking-tight">Day {dayIndex + 1}</h3>
                                    <p className="text-sm text-slate-500 font-bold uppercase">{format(date, 'MMM dd')}</p>
                                </div>
                                <button 
                                    onClick={() => handleRegenerateDayClick(dayIndex)}
                                    disabled={!!isRegenerating}
                                    className="p-2 bg-slate-50 hover:bg-primary/10 hover:text-primary rounded-xl text-slate-400 transition-colors shadow-sm"
                                    title="重新生成全日行程"
                                >
                                    <RefreshCw className={`w-5 h-5 ${isRegenerating === `day-${dayIndex}` ? 'animate-spin' : ''}`} />
                                </button>
                            </div>

                            {/* Accommodation Input */}
                            <div className="flex items-center gap-2 text-xs text-slate-600 bg-slate-50 p-2.5 rounded-xl mt-3 border border-slate-100 hover:border-accent/50 transition-colors">
                                <Home className="w-4 h-4 text-accent" />
                                <input 
                                    className="bg-transparent border-none p-0 w-full focus:ring-0 text-xs truncate font-bold placeholder:text-slate-300 text-slate-700"
                                    value={tripData.dailyAccommodations[dayIndex] || tripData.accommodation}
                                    onChange={(e) => handleAccommodationChange(dayIndex, e.target.value)}
                                    placeholder="輸入住宿地點..."
                                />
                            </div>
                        </div>
                    </div>
                );
            })}
         </div>
      </div>

      {/* Main Grid Scrollable Area */}
      <div className="flex-1 overflow-auto bg-white/50">
        <div className="flex min-w-max relative">
            {/* Time Column */}
            <div className="w-20 flex-none bg-white/80 backdrop-blur-sm border-r-2 border-slate-200 z-10 shadow-[4px_0_10px_-2px_rgba(0,0,0,0.05)]">
                {hours.map(h => (
                    <div key={h} className="h-44 border-b border-dashed border-slate-200 p-2 text-xs font-black text-slate-400 text-center sticky left-0 flex items-center justify-center">
                        {h}:00
                    </div>
                ))}
            </div>

            {/* Day Columns */}
            {days.map(dayIndex => {
                const dayActivities = getActivitiesForDay(dayIndex);
                return (
                    <div key={dayIndex} className="w-80 flex-none border-r-2 border-slate-200 relative bg-white/30 group/col">

                        {/* Day Watermark */}
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none overflow-hidden z-0">
                            <span className="text-[10rem] font-black text-slate-900/5 -rotate-12 select-none whitespace-nowrap">
                                DAY {dayIndex + 1}
                            </span>
                        </div>

                        {hours.map(hour => {
                            const timeStr = `${hour.toString().padStart(2, '0')}:00`;
                            const activitiesInSlot = dayActivities.filter(a => {
                                const activityHour = parseInt(a.startTime.split(':')[0]);
                                return activityHour === hour;
                            });

                            return (
                                <div 
                                    key={hour} 
                                    className="h-44 border-b border-slate-200/60 p-2 relative group/cell transition-colors hover:bg-primary/5 z-10"
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, dayIndex, timeStr)}
                                >
                                    {/* Empty Slot Add Button */}
                                    {activitiesInSlot.length === 0 && (
                                        <button 
                                            onClick={() => onAddItem(dayIndex, timeStr)}
                                            className="absolute inset-0 m-auto w-12 h-12 rounded-full bg-white border-2 border-dashed border-slate-300 text-slate-300 opacity-0 group-hover/cell:opacity-100 flex items-center justify-center hover:bg-primary hover:text-white hover:border-primary transition-all z-0 scale-75 group-hover/cell:scale-100 shadow-sm"
                                            title="新增行程"
                                        >
                                            <Plus className="w-6 h-6" />
                                        </button>
                                    )}

                                    {activitiesInSlot.map(activity => (
                                        <div
                                            key={activity.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, activity)}
                                            onClick={() => setSelectedActivity(activity)}
                                            className={`
                                                relative z-20 h-full rounded-2xl border-l-[6px] shadow-sm cursor-grab active:cursor-grabbing transition-all hover:shadow-xl hover:-translate-y-1 bg-white group/card overflow-hidden flex flex-col ring-1 ring-black/5
                                                ${activity.type === 'food' ? 'border-l-orange-400' : 
                                                  activity.type === 'sight' ? 'border-l-blue-400' : 
                                                  activity.type === 'shopping' ? 'border-l-pink-400' : 'border-l-emerald-400'}
                                            `}
                                        >
                                            {/* Thumbnail Background with overlay */}
                                            <div className="h-24 w-full relative overflow-hidden">
                                                 <img src={activity.imageUrl} alt="" className="w-full h-full object-cover transform group-hover/card:scale-110 transition-transform duration-700 ease-out" />
                                                 <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent"></div>

                                                 <div className="absolute top-1 right-1 flex gap-1 opacity-0 group-hover/card:opacity-100 transition-opacity">
                                                     <button 
                                                        onClick={(e) => { e.stopPropagation(); setIsRegenerating(activity.id); onRegenerateItem(activity); }}
                                                        className={`p-1.5 bg-white/90 rounded-full hover:bg-white text-slate-600 shadow-md ${isRegenerating === activity.id ? 'animate-spin' : ''}`}
                                                        title="更新此行程">
                                                        <RefreshCw className="w-3.5 h-3.5" />
                                                    </button>
                                                 </div>

                                                 <div className="absolute top-1 left-1 opacity-0 group-hover/card:opacity-100 transition-opacity">
                                                     <div className="p-1 bg-black/20 text-white rounded cursor-move">
                                                        <GripVertical className="w-4 h-4" />
                                                     </div>
                                                 </div>

                                                 <div className="absolute bottom-0 left-0 w-full p-2 flex justify-between items-end">
                                                     <span className="text-white font-bold text-xs drop-shadow-md bg-black/30 px-1.5 py-0.5 rounded backdrop-blur-sm">
                                                         {activity.startTime}
                                                     </span>
                                                     <button 
                                                        onClick={(e) => toggleStar(e, activity.id, activity.rating)}
                                                        className="hover:scale-110 transition-transform">
                                                        <Star className={`w-4 h-4 drop-shadow-md ${activity.rating === 5 ? 'fill-yellow-400 text-yellow-400' : 'text-white/50'}`} />
                                                     </button>
                                                 </div>
                                            </div>

                                            <div className="p-2.5 flex-1 flex flex-col justify-between bg-white">
                                                <h4 className="text-sm font-bold text-slate-800 leading-snug line-clamp-2">{activity.title}</h4>
                                                <div className="flex items-center gap-1 mt-1">
                                                    <span className={`text-[10px] px-2 py-0.5 rounded-md font-bold uppercase tracking-wide border border-black/5 ${getTypeColor(activity.type)}`}>
                                                        {activity.durationMinutes} min
                                                    </span>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            );
                        })}
                    </div>
                );
            })}
        </div>
      </div>

      {/* Activity Details Modal */}
      <Modal
        isOpen={!!selectedActivity}
        onClose={() => { setSelectedActivity(null); setPromptMode(false); }}
        title="行程詳情"
        footer={
            <div className="flex w-full items-center gap-2">
                <Button variant="danger" onClick={() => selectedActivity && handleDelete(selectedActivity.id)} className="px-3 rounded-xl">
                    <Trash2 className="w-4 h-4" />
                </Button>
                <div className="h-6 w-px bg-slate-200 mx-2"></div>

                {promptMode ? (
                     <div className="flex w-full gap-2 animate-in fade-in slide-in-from-right-5 duration-300">
                         <input 
                            className="flex-1 text-sm border-2 border-slate-200 rounded-xl px-3 py-2 focus:ring-2 focus:ring-primary focus:border-transparent outline-none"
                            placeholder="例如：轉做食壽司..."
                            value={customPrompt}
                            onChange={e => setCustomPrompt(e.target.value)}
                         />
                         <Button onClick={() => selectedActivity && handleRegenerateClick(selectedActivity)} isLoading={!!isRegenerating} className="rounded-xl">Go</Button>
                         <Button variant="ghost" onClick={() => setPromptMode(false)} className="rounded-xl"><X className="w-4 h-4"/></Button>
                     </div>
                ) : (
                    <>
                        <Button variant="secondary" onClick={() => setPromptMode(true)} className="flex-1 rounded-xl font-bold">自訂修改</Button>
                        <Button onClick={() => selectedActivity && handleRegenerateClick(selectedActivity)} isLoading={!!isRegenerating} className="flex-1 rounded-xl shadow-lg shadow-primary/30 font-bold">
                            <RefreshCw className="w-4 h-4 mr-2" /> 隨機更新
                        </Button>
                    </>
                )}
            </div>
        }
      >
        {selectedActivity && (
            <div className="space-y-5">
                <div className="relative rounded-2xl overflow-hidden shadow-xl h-56 group">
                    <img src={selectedActivity.imageUrl} className="w-full h-full object-cover transform transition-transform duration-1000 group-hover:scale-105" alt={selectedActivity.title} />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
                    <div className="absolute bottom-5 left-5 text-white right-5">
                        <div className="flex items-center gap-3 text-sm font-bold mb-2 opacity-90">
                            <div className="flex items-center bg-white/20 backdrop-blur-md rounded-lg px-2 py-1">
                                <Clock className="w-4 h-4 mr-1.5" />
                                {/* Editable Time Input */}
                                <input 
                                    type="time" 
                                    className="bg-transparent border-none p-0 text-white font-bold focus:ring-0 w-20 cursor-pointer text-sm"
                                    value={selectedActivity.startTime}
                                    onChange={(e) => handleTimeChange(e.target.value)}
                                />
                                <span className="mx-1">-</span>
                                <span>{addMinutes(selectedActivity.startTime, selectedActivity.durationMinutes)}</span>
                            </div>
                        </div>
                        <h2 className="text-3xl font-black tracking-tight leading-none mb-1">{selectedActivity.title}</h2>
                    </div>
                    <div className="absolute top-4 right-4 bg-white/20 backdrop-blur-md p-2 rounded-xl cursor-pointer hover:bg-white/30 transition-colors border border-white/30 shadow-lg"
                         onClick={(e) => toggleStar(e, selectedActivity.id, selectedActivity.rating)}>
                         {[1,2,3,4,5].map(star => (
                             <Star key={star} className={`w-5 h-5 inline-block ${star <= selectedActivity.rating ? 'fill-yellow-400 text-yellow-400 drop-shadow' : 'text-white/50'}`} />
                         ))}
                    </div>
                </div>

                <div className="space-y-4">
                    <p className="text-slate-700 text-lg leading-relaxed font-medium">{selectedActivity.description}</p>

                    <div className="grid grid-cols-1 gap-4">
                         <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 flex gap-4 hover:border-primary/30 transition-colors">
                            <div className="bg-white p-2.5 rounded-xl shadow-sm h-fit">
                                <MapPin className="w-5 h-5 text-primary" />
                            </div>
                            <div>
                                <h5 className="font-bold text-slate-900 text-sm mb-0.5">詳細地址</h5>
                                <p className="text-slate-600 text-sm leading-relaxed">{selectedActivity.location}</p>
                            </div>
                         </div>

                         <div className="bg-gradient-to-br from-accent/10 to-transparent p-5 rounded-2xl border border-accent/20 relative overflow-hidden">
                            <div className="absolute top-0 right-0 -mt-2 -mr-2 w-16 h-16 bg-accent/20 rounded-full blur-xl"></div>
                            <h5 className="font-bold text-yellow-700 text-sm mb-2 flex items-center gap-2 relative z-10"><Star className="w-4 h-4 fill-yellow-600" /> 推介原因</h5>
                            <p className="text-slate-800 text-sm italic font-medium relative z-10">“{selectedActivity.reason}”</p>
                         </div>

                        {(selectedActivity.tips || selectedActivity.transportInfo) && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {selectedActivity.tips && (
                                    <div className="bg-orange-50 p-4 rounded-2xl border border-orange-100">
                                        <h5 className="font-bold text-orange-700 text-sm mb-2">注意事項</h5>
                                        <p className="text-slate-600 text-xs leading-relaxed">{selectedActivity.tips}</p>
                                    </div>
                                )}
                                {selectedActivity.transportInfo && (
                                    <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
                                        <h5 className="font-bold text-blue-700 text-sm mb-2">交通建議</h5>
                                        <p className="text-slate-600 text-xs leading-relaxed">{selectedActivity.transportInfo}</p>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        )}
      </Modal>
    </div>
  );
};

function differenceInDays(start: string, end: string) {
    if(!start || !end) return 1;
    const d1 = new Date(start);
    const d2 = new Date(end);
    return Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24)) + 1;
}

function addMinutes(time: string, minutes: number): string {
    const [h, m] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m + minutes);
    return format(date, 'HH:mm');
}

export enum TravelStyle {
  RELAXED = 'Relaxed',
  FOODIE = 'Foodie',
  ADVENTURE = 'Adventure',
  ARTSY = 'Artsy/Cultural',
  SCENIC = 'Scenic',
  SIGHTSEEING = 'Sightseeing',
  SHOPPING = 'Shopping',
  FAMILY = 'Family',
}

export interface TripData {
  destination: string;
  arrivalDate: string;
  arrivalTime: string;
  departureDate: string;
  departureTime: string;
  adults: number;
  children: number;
  accommodation: string;
  dailyAccommodations: Record<number, string>; // Day index -> Address
  breakfastTime: string;
  selfDrive: boolean;
  styles: TravelStyle[];
  mustSees: string;
}

export interface Activity {
  id: string;
  dayIndex: number;
  startTime: string; // HH:MM
  durationMinutes: number;
  title: string;
  description: string;
  location: string;
  type: 'food' | 'sight' | 'shopping' | 'transport' | 'other';
  rating: number; // 1-5 stars (User set)
  tips?: string;
  transportInfo?: string;
  reason?: string;
  imageUrl?: string; // Placeholder or generated
  isLocked?: boolean; // If 5 stars, treated as locked during regeneration
}

export type Itinerary = Activity[];

export interface SavedTrip {
  id: string;
  name: string;
  tripData: TripData;
  itinerary: Itinerary;
  updatedAt: number;
}

export interface AppState {
  step: 'context' | 'planner' | 'overview';
  tripData: TripData;
  itinerary: Itinerary;
  isLoading: boolean;
  loadingMessage: string;
}

import React, { useState, useEffect } from 'react';
import { TripData, Itinerary, Activity, SavedTrip } from './types';
import { TripContext } from './views/TripContext';
import { ItineraryPlanner } from './views/ItineraryPlanner';
import { ItineraryOverview } from './views/ItineraryOverview';
import { generateInitialItinerary, regenerateActivity, regenerateDay, suggestGapActivity } from './services/geminiService';
import { LayoutGrid, Calendar, ArrowLeft, Save, FolderOpen, Trash2, Edit2, Clock, MapPin } from 'lucide-react';
import { Logo } from './components/Logo';
import { Modal } from './components/Modal';
import { Button } from './components/Button';
import { v4 as uuidv4 } from 'uuid';
import { format } from 'date-fns';

const INITIAL_TRIP_DATA: TripData = {
  destination: '',
  arrivalDate: '',
  arrivalTime: '10:00',
  departureDate: '',
  departureTime: '18:00',
  adults: 2, 
  children: 1, 
  accommodation: '',
  dailyAccommodations: {},
  breakfastTime: '09:00',
  selfDrive: false,
  styles: [],
  mustSees: '',
};

const App: React.FC = () => {
  const [step, setStep] = useState<'context' | 'planner' | 'overview'>('context');
  const [tripData, setTripData] = useState<TripData>(INITIAL_TRIP_DATA);
  const [itinerary, setItinerary] = useState<Itinerary>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Saved Trips State
  const [savedTrips, setSavedTrips] = useState<SavedTrip[]>([]);
  const [isSavedTripsModalOpen, setIsSavedTripsModalOpen] = useState(false);
  const [editingTripId, setEditingTripId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');

  // Load saved trips from local storage on mount
  useEffect(() => {
    const stored = localStorage.getItem('kw_saved_trips');
    if (stored) {
        try {
            setSavedTrips(JSON.parse(stored));
        } catch (e) {
            console.error("Failed to parse saved trips", e);
        }
    }
  }, []);

  // Save to local storage whenever savedTrips changes
  useEffect(() => {
    localStorage.setItem('kw_saved_trips', JSON.stringify(savedTrips));
  }, [savedTrips]);

  const handleTripContextComplete = async (data: TripData) => {
    setTripData(data);
    setIsGenerating(true);
    setError(null);
    try {
      const generatedItinerary = await generateInitialItinerary(data);
      setItinerary(generatedItinerary);
      setStep('planner');
    } catch (e) {
      console.error(e);
      setError("無法生成行程，請檢查 API Key 或網絡連接。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleRegenerateItem = async (item: Activity, promptOverride?: string) => {
    try {
      const dayActivities = itinerary.filter(a => a.dayIndex === item.dayIndex && a.id !== item.id);
      const newItem = await regenerateActivity(tripData, item, dayActivities, promptOverride);
      setItinerary(prev => prev.map(a => a.id === item.id ? newItem : a));
    } catch (e) {
      console.error(e);
      alert("更新失敗，請稍後再試。");
    }
  };

  const handleRegenerateDay = async (dayIndex: number) => {
    try {
      const currentDayActivities = itinerary.filter(a => a.dayIndex === dayIndex);
      const newDayActivities = await regenerateDay(tripData, dayIndex, currentDayActivities);

      setItinerary(prev => [
        ...prev.filter(a => a.dayIndex !== dayIndex),
        ...newDayActivities
      ]);
    } catch (e) {
      console.error(e);
      alert("更新全日行程失敗。");
    }
  };

  const handleAddItem = async (dayIndex: number, time: string) => {
    try {
        const newItem = await suggestGapActivity(tripData, dayIndex, time, 60);
        setItinerary(prev => [...prev, newItem].sort((a,b) => a.startTime.localeCompare(b.startTime)));
    } catch(e) {
        console.error(e);
    }
  };

  const handleMoveActivity = async (
    activityId: string, 
    newDayIndex: number, 
    newTime: string,
    oldDayIndex: number,
    oldTime: string,
    duration: number
  ) => {
    setItinerary(prev => {
        return prev.map(item => {
            if (item.id === activityId) {
                return { ...item, dayIndex: newDayIndex, startTime: newTime };
            }
            return item;
        }).sort((a, b) => a.startTime.localeCompare(b.startTime));
    });

    try {
        const gapActivity = await suggestGapActivity(tripData, oldDayIndex, oldTime, duration);
        setItinerary(prev => [...prev, gapActivity].sort((a, b) => a.startTime.localeCompare(b.startTime)));
    } catch (e) {
        console.error("Failed to auto-fill gap", e);
    }
  };

  // --- Saving Logic ---
  const handleSaveCurrentTrip = () => {
    if (itinerary.length === 0) {
        alert("目前的行程是空的，無法儲存。");
        return;
    }
    const defaultName = `${tripData.destination} 之旅 (${format(new Date(), 'yyyy-MM-dd')})`;
    const name = window.prompt("為您的行程命名：", defaultName);

    if (name) {
        const newTrip: SavedTrip = {
            id: uuidv4(),
            name,
            tripData,
            itinerary,
            updatedAt: Date.now()
        };
        setSavedTrips(prev => [newTrip, ...prev]);
        alert("行程已成功儲存到「我的行程庫」！");
    }
  };

  const handleLoadTrip = (trip: SavedTrip) => {
    if (window.confirm("載入此行程將會覆蓋當前未儲存的進度，確定嗎？")) {
        setTripData(trip.tripData);
        setItinerary(trip.itinerary);
        setStep('planner');
        setIsSavedTripsModalOpen(false);
    }
  };

  const handleDeleteTrip = (id: string) => {
    if (window.confirm("確定要刪除這個行程嗎？此操作無法還原。")) {
        setSavedTrips(prev => prev.filter(t => t.id !== id));
    }
  };

  const startEditingName = (trip: SavedTrip) => {
      setEditingTripId(trip.id);
      setEditName(trip.name);
  };

  const saveEditedName = (id: string) => {
      setSavedTrips(prev => prev.map(t => t.id === id ? { ...t, name: editName } : t));
      setEditingTripId(null);
  };

  return (
    <div className="min-h-screen flex flex-col bg-background text-slate-900">
      {/* Top Navigation Bar */}
      {step !== 'context' && (
        <header className="bg-white/90 backdrop-blur-xl border-b border-primary/20 sticky top-0 z-50 shadow-sm transition-all duration-300">
          <div className="max-w-7xl mx-auto px-4 h-18 flex flex-col md:flex-row items-center justify-between py-2 gap-2">
            <div className="flex items-center gap-6 w-full md:w-auto justify-between md:justify-start">
                <div className="hover:scale-105 transition-transform cursor-pointer" onClick={() => setStep('context')}>
                  <Logo />
                </div>
                <div className="hidden md:flex items-center gap-2 text-sm text-slate-500 border-l-2 pl-6 border-slate-200">
                     <span className="font-extrabold text-slate-800 text-lg">{tripData.destination}</span>
                     <span className="text-slate-300">•</span>
                     <span className="font-medium bg-slate-100 px-2 py-0.5 rounded-full">{tripData.adults} 大 {tripData.children} 小</span>
                </div>
            </div>

            <div className="flex items-center gap-3 overflow-x-auto w-full md:w-auto scrollbar-hide pb-1 md:pb-0">
                {/* View Switcher */}
                <div className="flex bg-slate-100/80 p-1.5 rounded-2xl shadow-inner border border-slate-200 flex-none">
                    <button 
                        onClick={() => setStep('planner')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${step === 'planner' ? 'bg-white shadow-md text-primary scale-105 ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-800 hover:bg-white/50'}`}
                    >
                        <LayoutGrid className="w-4 h-4" /> <span className="hidden sm:inline">行程細節</span>
                    </button>
                    <button 
                        onClick={() => setStep('overview')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all ${step === 'overview' ? 'bg-white shadow-md text-primary scale-105 ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-800 hover:bg-white/50'}`}
                    >
                        <Calendar className="w-4 h-4" /> <span className="hidden sm:inline">行程概覽</span>
                    </button>
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 flex-none">
                    <button 
                        onClick={handleSaveCurrentTrip}
                        className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-xl text-sm font-bold shadow-lg shadow-primary/20 hover:bg-primaryLight hover:text-slate-900 transition-all active:scale-95"
                        title="儲存當前行程"
                    >
                        <Save className="w-4 h-4" /> <span className="hidden sm:inline">儲存</span>
                    </button>

                    <button 
                        onClick={() => setIsSavedTripsModalOpen(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-white border-2 border-slate-100 text-slate-600 rounded-xl text-sm font-bold hover:border-primary/30 hover:text-primary transition-all active:scale-95"
                        title="我的行程庫"
                    >
                        <FolderOpen className="w-4 h-4" /> <span className="hidden sm:inline">我的行程</span>
                    </button>

                    <button 
                        onClick={() => setStep('context')} 
                        className="p-2.5 text-slate-400 hover:text-primary hover:bg-primary/5 rounded-xl transition-all"
                        title="修改設定"
                    >
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                </div>
            </div>
          </div>
        </header>
      )}

      {/* Main Content */}
      <main className="flex-1 relative flex flex-col">
        {error && (
            <div className="absolute top-4 left-1/2 transform -translate-x-1/2 bg-red-100 border border-red-400 text-red-700 px-6 py-3 rounded-full shadow-lg z-50 font-bold animate-bounce">
                {error}
            </div>
        )}

        {step === 'context' && (
            <div className="min-h-screen flex flex-col items-center justify-center bg-kiwi-pattern py-10">
                 <div className="mb-8 scale-150 transform hover:rotate-3 transition-transform duration-500">
                     <Logo />
                 </div>
                 <div className="mb-8">
                    <Button variant="secondary" onClick={() => setIsSavedTripsModalOpen(true)} className="rounded-full px-6 py-3 shadow-lg border-2 border-white/50 bg-white/80 backdrop-blur font-bold text-primary">
                        <FolderOpen className="w-5 h-5 mr-2" /> 打開我的行程庫
                    </Button>
                 </div>
                 <TripContext 
                    initialData={tripData} 
                    onComplete={handleTripContextComplete} 
                    isGenerating={isGenerating} 
                />
            </div>
        )}

        {step === 'planner' && (
          <ItineraryPlanner 
            tripData={tripData}
            itinerary={itinerary}
            onUpdateItinerary={setItinerary}
            onUpdateTripData={setTripData}
            onRegenerateItem={handleRegenerateItem}
            onRegenerateDay={handleRegenerateDay}
            onAddItem={handleAddItem}
            onMoveActivity={handleMoveActivity}
          />
        )}

        {step === 'overview' && (
            <ItineraryOverview tripData={tripData} itinerary={itinerary} />
        )}
      </main>

      {/* Saved Trips Modal */}
      <Modal
        isOpen={isSavedTripsModalOpen}
        onClose={() => { setIsSavedTripsModalOpen(false); setEditingTripId(null); }}
        title="我的行程庫"
      >
        <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-2">
            {savedTrips.length === 0 ? (
                <div className="text-center py-10 text-slate-400">
                    <FolderOpen className="w-12 h-12 mx-auto mb-3 opacity-20" />
                    <p>您還沒有儲存任何行程。</p>
                </div>
            ) : (
                savedTrips.map(trip => (
                    <div key={trip.id} className="bg-white border border-slate-100 rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow group relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-primary"></div>
                        <div className="flex justify-between items-start gap-4">
                            <div className="flex-1">
                                {editingTripId === trip.id ? (
                                    <div className="flex items-center gap-2 mb-2">
                                        <input 
                                            autoFocus
                                            className="border border-primary rounded px-2 py-1 text-sm font-bold w-full"
                                            value={editName}
                                            onChange={(e) => setEditName(e.target.value)}
                                        />
                                        <Button size="sm" onClick={() => saveEditedName(trip.id)} className="h-8 w-8 p-0"><Save className="w-3 h-3"/></Button>
                                    </div>
                                ) : (
                                    <h4 className="font-bold text-slate-800 text-lg mb-1 flex items-center gap-2">
                                        {trip.name}
                                        <button onClick={() => startEditingName(trip)} className="opacity-0 group-hover:opacity-100 transition-opacity p-1 text-slate-400 hover:text-primary">
                                            <Edit2 className="w-3 h-3" />
                                        </button>
                                    </h4>
                                )}

                                <div className="flex items-center gap-3 text-xs text-slate-500 font-medium">
                                    <span className="flex items-center gap-1"><MapPin className="w-3 h-3"/> {trip.tripData.destination}</span>
                                    <span className="flex items-center gap-1"><Clock className="w-3 h-3"/> 更新於: {format(trip.updatedAt, 'yyyy/MM/dd HH:mm')}</span>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                <Button 
                                    onClick={() => handleLoadTrip(trip)}
                                    className="bg-slate-50 text-primary hover:bg-primary hover:text-white border border-primary/20 text-xs px-3 py-1.5 h-auto rounded-lg"
                                >
                                    讀取
                                </Button>
                                <Button 
                                    variant="danger" 
                                    onClick={() => handleDeleteTrip(trip.id)}
                                    className="px-2 py-1.5 h-auto rounded-lg bg-red-50 text-red-500 border border-red-100 hover:bg-red-500 hover:text-white"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </Button>
                            </div>
                        </div>
                    </div>
                ))
            )}
        </div>
      </Modal>
    </div>
  );
};

export default App;

