  '55J9M2hD2K8': ['車', 'train', 'drive', '自駕', '交通', '空港', '機場'],
};

// Fallback images by type
const TYPE_FALLBACKS: Record<string, string> = {
  food: 'x00CzBt4Dfk',
  sight: 'EcN10-F0J7A',
  shopping: 'G8OB8R08Kj0',
  transport: '55J9M2hD2K8',
  other: 'nGrfKUSxc0U',
};

const getImageUrl = (title: string, type: string) => {
  const lowerTitle = title.toLowerCase();

  // Try to find a matching keyword
  for (const [imageId, keywords] of Object.entries(IMAGE_KEYWORDS)) {
    if (keywords.some(k => lowerTitle.includes(k))) {
      return `https://images.unsplash.com/photo-${imageId}?auto=format&fit=crop&w=600&q=80`;
    }
  }

  // Fallback to type
  const fallbackId = TYPE_FALLBACKS[type] || TYPE_FALLBACKS['other'];
  return `https://images.unsplash.com/photo-${fallbackId}?auto=format&fit=crop&w=600&q=80`;
};

// --- Schemas ---

const activitySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    startTime: { type: Type.STRING, description: "Start time in HH:MM format (24h)" },
    durationMinutes: { type: Type.INTEGER, description: "Duration in minutes" },
    title: { type: Type.STRING },
    description: { type: Type.STRING, description: "Short description of the activity" },
    location: { type: Type.STRING, description: "Address or Place Name" },
    type: { type: Type.STRING, enum: ["food", "sight", "shopping", "transport", "other"] },
    tips: { type: Type.STRING, description: "Important tips or warnings" },
    transportInfo: { type: Type.STRING, description: "How to get there from previous location or accommodation" },
    reason: { type: Type.STRING, description: "Why this was recommended based on user preferences" },
  },
  required: ["startTime", "durationMinutes", "title", "description", "location", "type", "transportInfo"],
};

const daySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    dayIndex: { type: Type.INTEGER },
    activities: {
      type: Type.ARRAY,
      items: activitySchema,
    },
  },
  required: ["dayIndex", "activities"],
};

const itinerarySchema: Schema = {
  type: Type.ARRAY,
  items: daySchema,
};


export const generateInitialItinerary = async (tripData: TripData): Promise<Itinerary> => {
  const ai = getAiClient();

  const daysCount = calculateDays(tripData.arrivalDate, tripData.departureDate);

  const prompt = `
    為前往 ${tripData.destination} 的旅行創建一個詳細的行程表。
    請全部使用繁體中文 (Traditional Chinese) 回覆。

    背景資料:
    - 到埗: ${tripData.arrivalDate} ${tripData.arrivalTime}
    - 回程: ${tripData.departureDate} ${tripData.departureTime}
    - 人數: ${tripData.adults} 大人, ${tripData.children} 小童
    - 主要住宿: ${tripData.accommodation}
    - 早餐時間: ${tripData.breakfastTime}
    - 自駕遊: ${tripData.selfDrive ? "是" : "否"}
    - 旅遊風格: ${tripData.styles.join(", ")}
    - 必去景點: ${tripData.mustSees}

    要求:
    - 計劃 ${daysCount} 天的行程。
    - 第一天在到埗時間後開始，最後一天在回程時間前結束。
    - 每天包括早餐、午餐和晚餐建議（除非在飛機上）。
    - 每天行程在早餐時間後 30 分鐘開始。
    - 考慮住宿地點的交通邏輯，盡量減少路程時間。
    - 每個活動必須有中文名稱及簡介。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        systemInstruction: "你是一位專業的繁體中文旅遊策劃師。請只返回 JSON 格式。",
      },
    });

    const rawData = JSON.parse(response.text || "[]");
    return parseGeminiResponseToItinerary(rawData);

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

export const regenerateActivity = async (
  tripData: TripData, 
  currentActivity: Activity, 
  dayActivities: Activity[],
  promptOverride?: string
): Promise<Activity> => {
  const ai = getAiClient();

  const prompt = `
    為前往 ${tripData.destination} 的行程重新生成一個活動。
    請使用繁體中文。
    要替換的現有活動: ${currentActivity.title} (${currentActivity.startTime})。

    當天其他活動: ${dayActivities.map(a => `${a.startTime}: ${a.title}`).join(", ")}。
    當天住宿: ${tripData.dailyAccommodations[currentActivity.dayIndex] || tripData.accommodation}。

    ${promptOverride ? `用戶特別要求: ${promptOverride}` : "建議: 提供一個符合時間段和地點流向的替代方案。不要重複現有的活動。"}

    只返回一個活動物件 (JSON)。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: activitySchema,
    },
  });

  const rawActivity = JSON.parse(response.text || "{}");
  return {
    ...currentActivity,
    ...rawActivity,
    id: uuidv4(),
    rating: 0,
    imageUrl: getImageUrl(rawActivity.title || currentActivity.title, rawActivity.type || 'other'),
  };
};

export const regenerateDay = async (
  tripData: TripData,
  dayIndex: number,
  currentActivities: Activity[]
): Promise<Activity[]> => {
  const ai = getAiClient();

  const lockedActivities = currentActivities.filter(a => a.rating === 5);

  const prompt = `
    重新生成 ${tripData.destination} 第 ${dayIndex + 1} 天的行程。
    請使用繁體中文。
    住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
    早餐: ${tripData.breakfastTime}。

    限制:
    - 必須保留這些已鎖定(5星)的活動於指定時間: ${JSON.stringify(lockedActivities.map(a => ({ time: a.startTime, title: a.title })))}。
    - 圍繞這些活動填補當天的其餘時間。
    - 確保流程順暢。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: daySchema,
    },
  });

  const rawData = JSON.parse(response.text || "{}");

  const newActivities = (rawData.activities || []).map((raw: any) => ({
    id: uuidv4(),
    dayIndex: dayIndex,
    startTime: raw.startTime,
    durationMinutes: raw.durationMinutes,
    title: raw.title,
    description: raw.description,
    location: raw.location,
    type: raw.type,
    rating: 0,
    tips: raw.tips,
    transportInfo: raw.transportInfo,
    reason: raw.reason,
    imageUrl: getImageUrl(raw.title, raw.type),
  }));

  let merged = [...newActivities];
  lockedActivities.forEach(locked => {
    merged = merged.filter(a => a.startTime !== locked.startTime);
    merged.push(locked);
  });

  return merged.sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const suggestGapActivity = async (
  tripData: TripData,
  dayIndex: number,
  startTime: string,
  availableMinutes: number
): Promise<Activity> => {
    const ai = getAiClient();
    const prompt = `
        建議一個行程空檔的短暫活動。
        地點: ${tripData.destination}。
        第 ${dayIndex + 1} 天。
        開始時間: ${startTime}。
        可用時間: ${availableMinutes} 分鐘。
        住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
        風格: ${tripData.styles.join(', ')}。
        限制: 必須在時間/地點上可行。例如 "Coffee break", "短暫散步", "便利店", "逛小店"。
        請使用繁體中文。
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: activitySchema,
        }
    });

    const raw = JSON.parse(response.text || "{}");
    return {
        id: uuidv4(),
        dayIndex,
        startTime: raw.startTime || startTime, 
        durationMinutes: Math.min(raw.durationMinutes, availableMinutes),
        title: raw.title,
        description: raw.description,
        location: raw.location,
        type: raw.type,
        rating: 0,
        tips: raw.tips,
        transportInfo: raw.transportInfo,
        reason: raw.reason,
        imageUrl: getImageUrl(raw.title, raw.type),
    };
}


// Utilities

function calculateDays(start: string, end: string) {
  if (!start || !end) return 1;
  const d1 = new Date(start);
  const d2 = new Date(end);
  const diffTime = Math.abs(d2.getTime() - d1.getTime());
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 
}

function parseGeminiResponseToItinerary(data: any[]): Itinerary {
  const itinerary: Itinerary = [];

  data.forEach((day: any) => {
    if (day.activities && Array.isArray(day.activities)) {
      day.activities.forEach((act: any) => {
        itinerary.push({
          id: uuidv4(),
          dayIndex: day.dayIndex !== undefined ? day.dayIndex - 1 : 0, 
          startTime: act.startTime,
          durationMinutes: act.durationMinutes,
          title: act.title,
          description: act.description,
          location: act.location,
          type: act.type,
          rating: 0,
          tips: act.tips,
          transportInfo: act.transportInfo,
          reason: act.reason,
          imageUrl: getImageUrl(act.title, act.type),
        });
      });
    }
  });

  return itinerary;
}

import React, { useState } from 'react';
import { TripData, Itinerary, Activity } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { MapPin, Clock, Star, RefreshCw, X, Plus, Home, Trash2, GripVertical, ExternalLink, Navigation, Edit, Info, Timer } from 'lucide-react';
import { format, addDays, parseISO } from 'date-fns';

interface ItineraryPlannerProps {
  tripData: TripData;
  itinerary: Itinerary;
  onUpdateItinerary: (newItinerary: Itinerary) => void;
  onUpdateTripData: (newData: TripData) => void;
  onRegenerateItem: (item: Activity, prompt?: string) => Promise<void>;
  onRegenerateDay: (dayIndex: number) => Promise<void>;
  onAddItem: (dayIndex: number, time: string) => Promise<void>;
  onMoveActivity: (id: string, newDay: number, newTime: string, oldDay: number, oldTime: string, duration: number) => Promise<void>;
}

const START_HOUR = 7;
const END_HOUR = 23;
const HOURS_COUNT = END_HOUR - START_HOUR + 1;
const PIXELS_PER_HOUR = 160; // 1 hour = 160px height

export const ItineraryPlanner: React.FC<ItineraryPlannerProps> = ({
  tripData,
  itinerary,
  onUpdateItinerary,
  onUpdateTripData,
  onRegenerateItem,
  onRegenerateDay,
  onAddItem,
  onMoveActivity
}) => {
  const [selectedActivity, setSelectedActivity] = useState<Activity | null>(null);
  const [draggedActivityId, setDraggedActivityId] = useState<string | null>(null);
  const [isRegenerating, setIsRegenerating] = useState<string | null>(null); 
  const [promptMode, setPromptMode] = useState(false);
  const [customPrompt, setCustomPrompt] = useState('');

  const days = Array.from({ length: differenceInDays(tripData.arrivalDate, tripData.departureDate) }, (_, i) => i);
  const hours = Array.from({ length: HOURS_COUNT }, (_, i) => i + START_HOUR);

  // --- Drag & Drop Logic ---
  const handleDragStart = (e: React.DragEvent, activityId: string) => {
    setDraggedActivityId(activityId);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', activityId);
    // Optional: Hide default drag image or style it
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetDayIndex: number, targetHour: number) => {
    e.preventDefault();
    const activityId = e.dataTransfer.getData('text/plain');
    if (!activityId) return;

    const activity = itinerary.find(a => a.id === activityId);
    if (!activity) return;

    const targetTime = `${targetHour.toString().padStart(2, '0')}:00`;

    if (activity.dayIndex === targetDayIndex && parseInt(activity.startTime.split(':')[0]) === targetHour) {
        setDraggedActivityId(null);
        return;
    }

    onMoveActivity(
        activity.id,
        targetDayIndex,
        targetTime,
        activity.dayIndex,
        activity.startTime,
        activity.durationMinutes
    );

    setDraggedActivityId(null);
  };

  const getActivitiesForDay = (dayIndex: number) => {
    return itinerary.filter(a => a.dayIndex === dayIndex);
  };

  // --- Calculations for Positioning ---
  const calculateTop = (time: string) => {
      const [h, m] = time.split(':').map(Number);
      const hoursFromStart = (h - START_HOUR) + (m / 60);
      return hoursFromStart * PIXELS_PER_HOUR;
  };

  const calculateHeight = (durationMinutes: number) => {
      // Precise duration mapping
      return (durationMinutes / 60) * PIXELS_PER_HOUR;
  };

  const toggleStar = (e: React.MouseEvent, id: string, current: number) => {
    e.stopPropagation();
    const newRating = current === 5 ? 0 : 5;
    const newItinerary = itinerary.map(a => a.id === id ? { ...a, rating: newRating } : a);
    onUpdateItinerary(newItinerary);
  };

  const handleDelete = (id: string) => {
    onUpdateItinerary(itinerary.filter(a => a.id !== id));
    setSelectedActivity(null);
  };

  const handleDetailsUpdate = (field: 'startTime' | 'durationMinutes', value: string) => {
    if (selectedActivity) {
      let updated = { ...selectedActivity };
      if (field === 'startTime') {
        updated.startTime = value;
      } else if (field === 'durationMinutes') {
        updated.durationMinutes = parseInt(value) || 30;
      }

      const newItinerary = itinerary.map(a => a.id === selectedActivity.id ? updated : a)
        .sort((a,b) => a.startTime.localeCompare(b.startTime));

      onUpdateItinerary(newItinerary);
      setSelectedActivity(updated);
    }
  }

  const handleRegenerateClick = async (item: Activity) => {
    setIsRegenerating(item.id);
    await onRegenerateItem(item, promptMode ? customPrompt : undefined);
    setIsRegenerating(null);
    setPromptMode(false);
    setCustomPrompt('');
    setSelectedActivity(null);
  };

  const handleRegenerateDayClick = async (dayIndex: number) => {
    if (window.confirm("重新生成這整天的行程？(已標記 5 星的項目將會保留)")) {
        setIsRegenerating(`day-${dayIndex}`);
        await onRegenerateDay(dayIndex);
        setIsRegenerating(null);
    }
  };

  const handleAccommodationChange = (dayIndex: number, val: string) => {
    onUpdateTripData({
        ...tripData,
        dailyAccommodations: {
            ...tripData.dailyAccommodations,
            [dayIndex]: val
        }
    });
  };

  // 3D Card Styles
  const cardGradient = (type: string) => {
    switch (type) {
        case 'food': return 'bg-gradient-to-br from-white to-orange-50 border-orange-200 shadow-orange-100';
        case 'sight': return 'bg-gradient-to-br from-white to-sky-50 border-sky-200 shadow-sky-100';
        case 'shopping': return 'bg-gradient-to-br from-white to-pink-50 border-pink-200 shadow-pink-100';
        default: return 'bg-gradient-to-br from-white to-emerald-50 border-emerald-200 shadow-emerald-100';
    }
  };

  return (
    <div className="h-full flex flex-col bg-transparent relative overflow-hidden">

      {/* Scrollable Container */}
      <div className="flex-1 overflow-auto pb-10">
        <div className="flex min-w-max px-4 pt-4">

            {/* Sticky Time Column */}
            <div className="sticky left-0 z-30 flex flex-col pt-32 w-20 bg-white/80 backdrop-blur-md rounded-2xl shadow-lg border border-white mr-4">
                 {hours.map(h => (
                    <div key={h} className="border-b border-dashed border-slate-300/50 p-2 text-xs font-black text-slate-400 text-center flex items-start justify-center" style={{ height: PIXELS_PER_HOUR }}>
                        <span className="bg-slate-100 px-2 py-1 rounded-md -mt-3">{h}:00</span>
                    </div>
                ))}
            </div>

            {/* Day Columns */}
            {days.map(dayIndex => {
                const date = addDays(parseISO(tripData.arrivalDate), dayIndex);
                const dayActivities = getActivitiesForDay(dayIndex);

                return (
                    <div key={dayIndex} className="w-80 flex-none flex flex-col mr-6 relative group/col">

                        {/* Column Watermark */}
                        <div className="absolute inset-0 z-0 flex items-center justify-center pointer-events-none overflow-hidden h-full">
                             <div className="text-[8rem] font-black text-slate-900/5 -rotate-90 whitespace-nowrap select-none transform translate-y-20 origin-center sticky top-1/3">
                                DAY {dayIndex + 1}
                            </div>
                        </div>

                        {/* Sticky Header */}
                        <div className="sticky top-0 z-30 mb-4 h-32">
                             <div className="bg-white/80 backdrop-blur-xl rounded-3xl border-2 border-white/50 shadow-xl p-4 transition-all hover:scale-[1.02] hover:shadow-2xl hover:border-primary/30 relative overflow-hidden h-full flex flex-col justify-between">
                                 <div className="absolute top-0 right-0 w-20 h-20 bg-gradient-to-bl from-primary/20 to-transparent rounded-bl-full -mr-4 -mt-4"></div>

                                 <div className="flex justify-between items-start relative z-10">
                                    <div>
                                        <h3 className="font-black text-slate-800 text-2xl tracking-tight drop-shadow-sm">DAY {dayIndex + 1}</h3>
                                        <p className="text-sm text-slate-500 font-bold uppercase tracking-wide">{format(date, 'MMM dd, EEEE')}</p>
                                    </div>
                                    <button 
                                        onClick={() => handleRegenerateDayClick(dayIndex)}
                                        disabled={!!isRegenerating}
                                        className="p-2.5 bg-white hover:bg-primary hover:text-white rounded-xl text-slate-400 transition-all shadow-sm border border-slate-100 active:scale-95"
                                        title="重新生成全日行程"
                                    >
                                        <RefreshCw className={`w-4 h-4 ${isRegenerating === `day-${dayIndex}` ? 'animate-spin' : ''}`} />
                                    </button>
                                </div>

                                {/* Accommodation Input */}
                                <div className="relative group/input">
                                    <div className="absolute inset-y-0 left-2 flex items-center pointer-events-none text-slate-400">
                                        <Home className="w-4 h-4" />
                                    </div>
                                    <input 
                                        className="w-full bg-slate-50/80 border border-slate-200 rounded-xl py-2 pl-8 pr-2 text-xs font-bold text-slate-700 focus:ring-2 focus:ring-primary/50 focus:bg-white outline-none transition-all placeholder:text-slate-300"
                                        value={tripData.dailyAccommodations[dayIndex] || tripData.accommodation}
                                        onChange={(e) => handleAccommodationChange(dayIndex, e.target.value)}
                                        placeholder="輸入住宿地點..."
                                    />
                                </div>
                            </div>
                        </div>

                        {/* Timeline Grid (Absolute Positioning Context) */}
                        <div className="relative w-full z-10" style={{ height: HOURS_COUNT * PIXELS_PER_HOUR }}>

                            {/* Background Grid Lines (Drop Targets) */}
                            {hours.map(hour => (
                                <div 
                                    key={hour}
                                    className="absolute w-full border-b border-white/40 hover:bg-white/10 transition-colors z-0"
                                    style={{ 
                                        top: (hour - START_HOUR) * PIXELS_PER_HOUR, 
                                        height: PIXELS_PER_HOUR 
