                                    {/* Add Button Area */}
                                    <div className="absolute inset-0 opacity-0 hover:opacity-100 flex items-center justify-center transition-opacity pointer-events-none">
                                        <button 
                                            onClick={() => onAddItem(dayIndex, `${hour.toString().padStart(2, '0')}:00`)}
                                            className="bg-white/80 text-primary p-2 rounded-full shadow pointer-events-auto hover:scale-110 transition-transform"
                                        >
                                            <Plus className="w-5 h-5" />
                                        </button>
                                    </div>
