];

const getImageUrl = (title: string, type: string) => {
  const lowerTitle = title.toLowerCase();

  // Keyword Mapping
  const keywords: Record<string, string> = {
    '東京': 'tokyo', 'tokyo': 'tokyo', '涉谷': 'tokyo', '新宿': 'tokyo',
    '大阪': 'osaka', 'osaka': 'osaka', '難波': 'osaka', '道頓堀': 'osaka',
    '京都': 'kyoto', 'kyoto': 'kyoto', '清水寺': 'kyoto', '稻荷': 'kyoto',
    '北海道': 'hokkaido', '札幌': 'hokkaido', '小樽': 'hokkaido',
    '富士': 'fuji', 'fuji': 'fuji', '河口湖': 'fuji',

    '迪士尼': 'disney', 'disney': 'disney',
    '環球': 'universal', 'universal': 'universal', 'usj': 'universal',

    '水族館': 'aquarium', 'aquarium': 'aquarium',
    '動物園': 'zoo', 'zoo': 'zoo',
    '美術館': 'art', '藝術': 'art', 'teamlab': 'art', '博物館': 'art',
    '溫泉': 'onsen', 'onsen': 'onsen',
    '購物': 'shopping', '百貨': 'shopping', 'outlet': 'shopping', '商場': 'shopping', 'donki': 'shopping',

    '壽司': 'sushi', 'sushi': 'sushi', '海鮮': 'sushi',
    '拉麵': 'ramen', 'ramen': 'ramen', '烏冬': 'ramen',
    '燒肉': 'beef', '牛': 'beef', 'wagyu': 'beef',
    '咖啡': 'cafe', 'cafe': 'cafe', '甜點': 'cafe', 'starbucks': 'cafe',
    '居酒屋': 'izakaya', '酒': 'izakaya',
    '市場': 'market', '築地': 'market',

    '機場': 'airport', '空港': 'airport', 'airport': 'airport',
    '新幹線': 'train', '鐵路': 'train', '站': 'train'
  };

  // 1. Try Keyword Match
  for (const [key, category] of Object.entries(keywords)) {
    if (lowerTitle.includes(key)) {
      const images = IMAGE_LIBRARY[category];
      const index = Math.abs(hashCode(title)) % images.length;
      return `https://images.unsplash.com/photo-${images[index]}?auto=format&fit=crop&w=600&q=80`;
    }
  }

  // 2. Deterministic Fallback from General Pool
  // We use the hash of the title to ensure the same activity always gets the same random image
  const poolIndex = Math.abs(hashCode(title)) % GENERAL_POOL.length;
  return `https://images.unsplash.com/photo-${GENERAL_POOL[poolIndex]}?auto=format&fit=crop&w=600&q=80`;
};

// Simple hash function for deterministic image selection
function hashCode(str: string) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return hash;
}

// --- Schemas ---

const activitySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    startTime: { type: Type.STRING, description: "Start time in HH:MM format (24h)" },
    durationMinutes: { type: Type.INTEGER, description: "Duration in minutes" },
    title: { type: Type.STRING },
    description: { type: Type.STRING, description: "Short description of the activity" },
    location: { type: Type.STRING, description: "Address or Place Name" },
    type: { type: Type.STRING, enum: ["food", "sight", "shopping", "transport", "other"] },
    tips: { type: Type.STRING, description: "Important tips or warnings" },
    transportInfo: { type: Type.STRING, description: "How to get there from previous location or accommodation" },
    reason: { type: Type.STRING, description: "Why this was recommended based on user preferences" },
  },
  required: ["startTime", "durationMinutes", "title", "description", "location", "type", "transportInfo"],
};

const daySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    dayIndex: { type: Type.INTEGER },
    activities: {
      type: Type.ARRAY,
      items: activitySchema,
    },
  },
  required: ["dayIndex", "activities"],
};

const itinerarySchema: Schema = {
  type: Type.ARRAY,
  items: daySchema,
};


export const generateInitialItinerary = async (tripData: TripData): Promise<Itinerary> => {
  const ai = getAiClient();

  const daysCount = calculateDays(tripData.arrivalDate, tripData.departureDate);

  const prompt = `
    為前往 ${tripData.destination} 的旅行創建一個詳細的行程表。
    請全部使用繁體中文 (Traditional Chinese) 回覆。

    背景資料:
    - 到埗: ${tripData.arrivalDate} ${tripData.arrivalTime}
    - 回程: ${tripData.departureDate} ${tripData.departureTime}
    - 人數: ${tripData.adults} 大人, ${tripData.children} 小童
    - 主要住宿: ${tripData.accommodation}
    - 早餐時間: ${tripData.breakfastTime}
    - 自駕遊: ${tripData.selfDrive ? "是" : "否"}
    - 旅遊風格: ${tripData.styles.join(", ")}
    - 必去景點: ${tripData.mustSees}

    要求:
    - 計劃 ${daysCount} 天的行程。
    - 第一天在到埗時間後開始，最後一天在回程時間前結束。
    - 每天包括早餐、午餐和晚餐建議（除非在飛機上）。
    - 每天行程在早餐時間後 30 分鐘開始。
    - 考慮住宿地點的交通邏輯，盡量減少路程時間。
    - 每個活動必須有中文名稱及簡介。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        systemInstruction: "你是一位專業的繁體中文旅遊策劃師。請只返回 JSON 格式。",
      },
    });

    const rawData = JSON.parse(response.text || "[]");
    return parseGeminiResponseToItinerary(rawData);

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

export const regenerateActivity = async (
  tripData: TripData, 
  currentActivity: Activity, 
  dayActivities: Activity[],
  promptOverride?: string
): Promise<Activity> => {
  const ai = getAiClient();

  const prompt = `
    為前往 ${tripData.destination} 的行程重新生成一個活動。
    請使用繁體中文。
    要替換的現有活動: ${currentActivity.title} (${currentActivity.startTime})。

    當天其他活動: ${dayActivities.map(a => `${a.startTime}: ${a.title}`).join(", ")}。
    當天住宿: ${tripData.dailyAccommodations[currentActivity.dayIndex] || tripData.accommodation}。

    ${promptOverride ? `用戶特別要求: ${promptOverride}` : "建議: 提供一個符合時間段和地點流向的替代方案。不要重複現有的活動。"}

    只返回一個活動物件 (JSON)。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: activitySchema,
    },
  });

  const rawActivity = JSON.parse(response.text || "{}");
  return {
    ...currentActivity,
    ...rawActivity,
    id: uuidv4(),
    rating: 0,
    imageUrl: getImageUrl(rawActivity.title || currentActivity.title, rawActivity.type || 'other'),
  };
};

export const regenerateDay = async (
  tripData: TripData,
  dayIndex: number,
  currentActivities: Activity[]
): Promise<Activity[]> => {
  const ai = getAiClient();

  const lockedActivities = currentActivities.filter(a => a.rating === 5);

  const prompt = `
    重新生成 ${tripData.destination} 第 ${dayIndex + 1} 天的行程。
    請使用繁體中文。
    住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
    早餐: ${tripData.breakfastTime}。

    限制:
    - 必須保留這些已鎖定(5星)的活動於指定時間: ${JSON.stringify(lockedActivities.map(a => ({ time: a.startTime, title: a.title })))}。
    - 圍繞這些活動填補當天的其餘時間。
    - 確保流程順暢。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: daySchema,
    },
  });

  const rawData = JSON.parse(response.text || "{}");

  const newActivities = (rawData.activities || []).map((raw: any) => ({
    id: uuidv4(),
    dayIndex: dayIndex,
    startTime: raw.startTime,
    durationMinutes: raw.durationMinutes,
    title: raw.title,
    description: raw.description,
    location: raw.location,
    type: raw.type,
    rating: 0,
    tips: raw.tips,
    transportInfo: raw.transportInfo,
    reason: raw.reason,
    imageUrl: getImageUrl(raw.title, raw.type),
  }));

  let merged = [...newActivities];
  lockedActivities.forEach(locked => {
    merged = merged.filter(a => a.startTime !== locked.startTime);
    merged.push(locked);
  });

  return merged.sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const suggestGapActivity = async (
  tripData: TripData,
  dayIndex: number,
  startTime: string,
  availableMinutes: number
): Promise<Activity> => {
    const ai = getAiClient();
    const prompt = `
        建議一個行程空檔的短暫活動。
        地點: ${tripData.destination}。
        第 ${dayIndex + 1} 天。
        開始時間: ${startTime}。
        可用時間: ${availableMinutes} 分鐘。
        住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
        風格: ${tripData.styles.join(', ')}。
        限制: 必須在時間/地點上可行。例如 "Coffee break", "短暫散步", "便利店", "逛小店"。
        請使用繁體中文。
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: activitySchema,
        }
    });

    const raw = JSON.parse(response.text || "{}");
    return {
        id: uuidv4(),
        dayIndex,
        startTime: raw.startTime || startTime, 
        durationMinutes: Math.min(raw.durationMinutes, availableMinutes),
        title: raw.title,
        description: raw.description,
        location: raw.location,
        type: raw.type,
        rating: 0,
        tips: raw.tips,
        transportInfo: raw.transportInfo,
        reason: raw.reason,
        imageUrl: getImageUrl(raw.title, raw.type),
    };
}


// Utilities

function calculateDays(start: string, end: string) {
  if (!start || !end) return 1;
  const d1 = new Date(start);
  const d2 = new Date(end);
  const diffTime = Math.abs(d2.getTime() - d1.getTime());
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 
}

function parseGeminiResponseToItinerary(data: any[]): Itinerary {
  const itinerary: Itinerary = [];

  data.forEach((day: any) => {
    if (day.activities && Array.isArray(day.activities)) {
      day.activities.forEach((act: any) => {
        itinerary.push({
          id: uuidv4(),
          dayIndex: day.dayIndex !== undefined ? day.dayIndex - 1 : 0, 
          startTime: act.startTime,
          durationMinutes: act.durationMinutes,
          title: act.title,
          description: act.description,
          location: act.location,
          type: act.type,
          rating: 0,
          tips: act.tips,
          transportInfo: act.transportInfo,
          reason: act.reason,
          imageUrl: getImageUrl(act.title, act.type),
        });
      });
    }
  });

  return itinerary;
}

import React, { useState } from 'react';
import { TripData, Itinerary, Activity } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { MapPin, Clock, Star, RefreshCw, X, Plus, Home, Trash2, GripVertical, ExternalLink, Navigation, Edit, Info, Timer } from 'lucide-react';
import { format, addDays, parseISO } from 'date-fns';

interface ItineraryPlannerProps {
  tripData: TripData;
  itinerary: Itinerary;
  onUpdateItinerary: (newItinerary: Itinerary) => void;
  onUpdateTripData: (newData: TripData) => void;
  onRegenerateItem: (item: Activity, prompt?: string) => Promise<void>;
  onRegenerateDay: (dayIndex: number) => Promise<void>;
  onAddItem: (dayIndex: number, time: string) => Promise<void>;
  onMoveActivity: (id: string, newDay: number, newTime: string, oldDay: number, oldTime: string, duration: number) => Promise<void>;
}

const START_HOUR = 7;
const END_HOUR = 23;
const HOURS_COUNT = END_HOUR - START_HOUR + 1;
const PIXELS_PER_HOUR = 160; // 1 hour = 160px height
const HEADER_HEIGHT = 80; // Fixed height for the day headers

export const ItineraryPlanner: React.FC<ItineraryPlannerProps> = ({
  tripData,
  itinerary,
  onUpdateItinerary,
  onUpdateTripData,
  onRegenerateItem,
  onRegenerateDay,
  onAddItem,
  onMoveActivity
}) => {
  const [selectedActivity, setSelectedActivity] = useState<Activity | null>(null);
  const [draggedActivityId, setDraggedActivityId] = useState<string | null>(null);
  const [isRegenerating, setIsRegenerating] = useState<string | null>(null); 
  const [promptMode, setPromptMode] = useState(false);
  const [customPrompt, setCustomPrompt] = useState('');

  const days = Array.from({ length: differenceInDays(tripData.arrivalDate, tripData.departureDate) }, (_, i) => i);
  const hours = Array.from({ length: HOURS_COUNT }, (_, i) => i + START_HOUR);

  // --- Drag & Drop Logic ---
  const handleDragStart = (e: React.DragEvent, activityId: string) => {
    setDraggedActivityId(activityId);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', activityId);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetDayIndex: number, targetHour: number) => {
    e.preventDefault();
    const activityId = e.dataTransfer.getData('text/plain');
    if (!activityId) return;

    const activity = itinerary.find(a => a.id === activityId);
    if (!activity) return;

    const targetTime = `${targetHour.toString().padStart(2, '0')}:00`;

    if (activity.dayIndex === targetDayIndex && parseInt(activity.startTime.split(':')[0]) === targetHour) {
        setDraggedActivityId(null);
        return;
    }

    onMoveActivity(
        activity.id,
        targetDayIndex,
        targetTime,
        activity.dayIndex,
        activity.startTime,
        activity.durationMinutes
    );

    setDraggedActivityId(null);
  };

  const getActivitiesForDay = (dayIndex: number) => {
    return itinerary.filter(a => a.dayIndex === dayIndex);
  };

  // --- Calculations for Positioning ---
  const calculateTop = (time: string) => {
      const [h, m] = time.split(':').map(Number);
      const hoursFromStart = (h - START_HOUR) + (m / 60);
      return hoursFromStart * PIXELS_PER_HOUR;
  };

  const calculateHeight = (durationMinutes: number) => {
      return (durationMinutes / 60) * PIXELS_PER_HOUR;
  };

  const toggleStar = (e: React.MouseEvent, id: string, current: number) => {
    e.stopPropagation();
    const newRating = current === 5 ? 0 : 5;
    const newItinerary = itinerary.map(a => a.id === id ? { ...a, rating: newRating } : a);
    onUpdateItinerary(newItinerary);
  };

  const handleDelete = (id: string) => {
    onUpdateItinerary(itinerary.filter(a => a.id !== id));
    setSelectedActivity(null);
  };

  const handleDetailsUpdate = (field: 'startTime' | 'durationMinutes', value: string) => {
    if (selectedActivity) {
      let updated = { ...selectedActivity };
      if (field === 'startTime') {
        updated.startTime = value;
      } else if (field === 'durationMinutes') {
        updated.durationMinutes = parseInt(value) || 30;
      }

      const newItinerary = itinerary.map(a => a.id === selectedActivity.id ? updated : a)
        .sort((a,b) => a.startTime.localeCompare(b.startTime));

      onUpdateItinerary(newItinerary);
      setSelectedActivity(updated);
    }
  }

  const handleRegenerateClick = async (item: Activity) => {
    setIsRegenerating(item.id);
    await onRegenerateItem(item, promptMode ? customPrompt : undefined);
    setIsRegenerating(null);
    setPromptMode(false);
    setCustomPrompt('');
    setSelectedActivity(null);
  };

  const handleRegenerateDayClick = async (dayIndex: number) => {
    if (window.confirm("重新生成這整天的行程？(已標記 5 星的項目將會保留)")) {
        setIsRegenerating(`day-${dayIndex}`);
        await onRegenerateDay(dayIndex);
        setIsRegenerating(null);
    }
  };

  const handleAccommodationChange = (dayIndex: number, val: string) => {
    onUpdateTripData({
        ...tripData,
        dailyAccommodations: {
            ...tripData.dailyAccommodations,
            [dayIndex]: val
        }
    });
  };

  // 3D Card Styles
  const cardGradient = (type: string) => {
    switch (type) {
        case 'food': return 'bg-gradient-to-br from-white to-orange-50 border-orange-200 shadow-orange-100/50';
        case 'sight': return 'bg-gradient-to-br from-white to-sky-50 border-sky-200 shadow-sky-100/50';
        case 'shopping': return 'bg-gradient-to-br from-white to-pink-50 border-pink-200 shadow-pink-100/50';
        default: return 'bg-gradient-to-br from-white to-emerald-50 border-emerald-200 shadow-emerald-100/50';
    }
  };

  return (
    <div className="h-full flex flex-col bg-transparent relative overflow-hidden">

      {/* Scrollable Container */}
      <div className="flex-1 overflow-auto pb-10 relative">
        <div className="flex min-w-max px-4">

            {/* Sticky Time Column */}
            <div className="sticky left-0 z-40 flex flex-col w-14 mr-2 bg-transparent pointer-events-none pt-[88px] group">
                 {/* 88px = HEADER_HEIGHT (80px) + Margin (8px) roughly */}
                 <div className="bg-white/95 backdrop-blur-md rounded-xl shadow-lg border border-slate-200/60 overflow-hidden pointer-events-auto">
                    {hours.map(h => (
                        <div key={h} className="border-b border-slate-100 text-[10px] font-bold text-slate-400 text-center flex items-start justify-center" style={{ height: PIXELS_PER_HOUR }}>
                            <span className="bg-slate-50 px-1.5 py-0.5 rounded -mt-2.5 shadow-sm">{h}:00</span>
                        </div>
                    ))}
                 </div>
            </div>

            {/* Day Columns */}
            {days.map(dayIndex => {
                const date = addDays(parseISO(tripData.arrivalDate), dayIndex);
                const dayActivities = getActivitiesForDay(dayIndex);

                return (
                    <div key={dayIndex} className="w-80 flex-none flex flex-col mr-6 relative group/col">

                        {/* 1. Sticky Header - Strictly sticky to the top of this container */}
                        <div className="sticky top-0 z-50 bg-gradient-to-b from-white/90 to-transparent pb-2 pt-2" style={{ height: HEADER_HEIGHT }}>
                             <div className="bg-white/90 backdrop-blur-xl rounded-xl border border-primary/20 shadow-lg p-2 flex justify-between items-center transition-all h-full">
                                <div className="flex items-center gap-3">
                                    <div className="bg-primary text-white text-sm font-black px-2.5 py-1.5 rounded-lg shadow-sm">D{dayIndex + 1}</div>
                                    <div className="flex flex-col">
                                        <span className="text-sm font-bold text-slate-800">{format(date, 'MMM dd')}</span>
                                        <span className="text-[10px] text-slate-400 font-bold uppercase">{format(date, 'EEEE')}</span>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => handleRegenerateDayClick(dayIndex)}
                                    disabled={!!isRegenerating}
                                    className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 transition-colors"
                                    title="重新生成全日行程"
                                >
                                    <RefreshCw className={`w-3.5 h-3.5 ${isRegenerating === `day-${dayIndex}` ? 'animate-spin' : ''}`} />
                                </button>
                             </div>
                        </div>

                        {/* 2. Scrollable Accommodation Input (Not Sticky, flows with content) */}
                        <div className="mb-2 relative group/input px-1">
                            <div className="relative">
                                <div className="absolute inset-y-0 left-2 flex items-center pointer-events-none text-slate-400">
                                    <Home className="w-3.5 h-3.5" />
                                </div>
                                <input 
                                    className="w-full bg-white/60 border border-slate-200 rounded-lg py-1.5 pl-8 pr-2 text-xs font-medium text-slate-600 focus:ring-2 focus:ring-primary/50 focus:bg-white outline-none transition-all placeholder:text-slate-400 shadow-sm"
                                    value={tripData.dailyAccommodations[dayIndex] || tripData.accommodation}
                                    onChange={(e) => handleAccommodationChange(dayIndex, e.target.value)}
                                    placeholder="住宿地點..."
                                />
                            </div>
                        </div>

                        {/* 3. Timeline Grid */}
                        <div className="relative w-full z-10 bg-slate-50/50 rounded-2xl border border-slate-200" style={{ height: HOURS_COUNT * PIXELS_PER_HOUR }}>

                            {/* Grid Lines */}
                            {hours.map(hour => (
                                <div 
                                    key={hour}
                                    className="absolute w-full border-b border-slate-200/60 z-0 group/slot"
                                    style={{ 
                                        top: (hour - START_HOUR) * PIXELS_PER_HOUR, 
                                        height: PIXELS_PER_HOUR 
                                    }}
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, dayIndex, hour)}
                                >
                                    {/* Half-hour dashed line */}
                                    <div className="absolute top-1/2 w-full border-b border-dashed border-slate-300/40"></div>

                                    {/* Add Button Area */}
                                    <div className="absolute inset-0 opacity-0 group-hover/slot:opacity-100 flex items-center justify-center transition-opacity pointer-events-none">
                                        <button 
                                            onClick={() => onAddItem(dayIndex, `${hour.toString().padStart(2, '0')}:00`)}
                                            className="bg-primary/90 text-white p-2 rounded-full shadow-lg pointer-events-auto hover:scale-110 transition-transform"
                                        >
                                            <Plus className="w-5 h-5" />
                                        </button>
                                    </div>
                                </div>
                            ))}

                            {/* Activities */}
                            {dayActivities.map(activity => {
                                const top = calculateTop(activity.startTime);
                                const height = calculateHeight(activity.durationMinutes);
                                const isShort = activity.durationMinutes < 45;

                                return (
                                    <div
                                        key={activity.id}
                                        draggable
                                        onDragStart={(e) => handleDragStart(e, activity.id)}
                                        onClick={() => setSelectedActivity(activity)}
                                        className={`
                                            absolute w-full px-1 z-10 transition-all duration-300 select-none cursor-move active:cursor-grabbing
                                            ${draggedActivityId === activity.id ? 'opacity-50 z-50 scale-105' : 'hover:z-20 hover:scale-[1.03]'}
                                        `}
                                        style={{ top: `${top}px`, height: `${Math.max(height, 30)}px` }}
                                    >
                                        <div className={`
                                            w-full h-full rounded-xl border shadow-sm group/card overflow-hidden flex flex-col pointer-events-auto
                                            ${cardGradient(activity.type)}
                                        `}>
                                            {/* Condensed View for short items */}
                                            {isShort ? (
                                                <div className="flex h-full items-center p-2 gap-2 bg-white/60 backdrop-blur-sm">
                                                     <div className="w-8 h-8 flex-none rounded-md overflow-hidden relative shadow-sm">
                                                        <img src={activity.imageUrl} className="w-full h-full object-cover pointer-events-none" />
                                                     </div>
                                                     <div className="min-w-0 flex-1">
                                                         <div className="flex justify-between items-center">
                                                            <h4 className="font-bold text-xs text-slate-800 truncate pointer-events-none">{activity.title}</h4>
                                                            <span className="text-[10px] font-bold text-slate-500">{activity.startTime}</span>
                                                         </div>
                                                     </div>
                                                </div>
                                            ) : (
                                                /* Full View */
                                                <>
                                                    <div className="h-3/5 relative overflow-hidden pointer-events-none">
                                                        <img src={activity.imageUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover/card:scale-110" />
                                                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                                                        <div className="absolute bottom-2 left-2 flex items-center gap-2">
                                                            <span className="text-white text-xs font-bold bg-black/30 backdrop-blur px-2 py-0.5 rounded">
                                                                {activity.startTime}
                                                            </span>
                                                            <span className="text-white text-[10px] bg-white/20 px-1.5 py-0.5 rounded">
                                                                {activity.durationMinutes}m
                                                            </span>
                                                        </div>
                                                        <button 
                                                            onClick={(e) => toggleStar(e, activity.id, activity.rating)}
                                                            className="absolute top-2 right-2 hover:scale-110 transition-transform pointer-events-auto"
                                                        >
                                                            <Star className={`w-4 h-4 drop-shadow-md ${activity.rating === 5 ? 'fill-yellow-400 text-yellow-400' : 'text-white/50'}`} />
                                                        </button>

                                                        <div className="absolute top-2 left-2 opacity-0 group-hover/card:opacity-100 transition-opacity">
                                                            <span className="p-1 bg-black/20 text-white rounded backdrop-blur"><GripVertical className="w-3 h-3" /></span>
                                                        </div>
                                                    </div>
                                                    <div className="flex-1 p-2 bg-white/50 backdrop-blur-sm flex flex-col justify-center pointer-events-none">
                                                        <h4 className="font-bold text-slate-800 text-xs leading-tight line-clamp-2">{activity.title}</h4>
                                                        <div className="mt-1 flex gap-1">
                                                             <span className="text-[10px] text-slate-500 bg-white/50 px-1.5 rounded">{activity.type}</span>
                                                        </div>
                                                    </div>
                                                </>
                                            )}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                );
            })}

            <div className="w-10 flex-none"></div>
        </div>
      </div>

      {/* Activity Details Modal */}
      <Modal
        isOpen={!!selectedActivity}
        onClose={() => { setSelectedActivity(null); setPromptMode(false); }}
        title="行程詳情"
        footer={
            <div className="flex w-full items-center gap-3">
                <Button variant="danger" onClick={() => selectedActivity && handleDelete(selectedActivity.id)} className="px-3 rounded-xl shadow-lg shadow-red-500/20">
                    <Trash2 className="w-4 h-4" />
                </Button>
                <div className="h-8 w-px bg-slate-200 mx-1"></div>

                {promptMode ? (
                     <div className="flex w-full gap-2 animate-in fade-in slide-in-from-right-5 duration-300">
                         <input 
                            className="flex-1 text-sm border-2 border-slate-200 rounded-xl px-3 py-2 focus:ring-2 focus:ring-primary focus:border-transparent outline-none shadow-inner"
                            placeholder="例如：轉做食壽司..."
                            value={customPrompt}
                            onChange={e => setCustomPrompt(e.target.value)}
                         />
                         <Button onClick={() => selectedActivity && handleRegenerateClick(selectedActivity)} isLoading={!!isRegenerating} className="rounded-xl">Go</Button>
                         <Button variant="ghost" onClick={() => setPromptMode(false)} className="rounded-xl"><X className="w-4 h-4"/></Button>
                     </div>
                ) : (
                    <>
                        <Button variant="secondary" onClick={() => setPromptMode(true)} className="flex-1 rounded-xl font-bold border-2 hover:border-primary hover:text-primary transition-all">
                            <Edit className="w-4 h-4 mr-2" /> 自訂修改
                        </Button>
                        <Button onClick={() => selectedActivity && handleRegenerateClick(selectedActivity)} isLoading={!!isRegenerating} className="flex-1 rounded-xl shadow-lg shadow-primary/30 font-bold bg-gradient-to-r from-primary to-primaryLight hover:scale-105 transition-transform">
                            <RefreshCw className="w-4 h-4 mr-2" /> 隨機更新
                        </Button>
                    </>
                )}
            </div>
        }
      >
        {selectedActivity && (
            <div className="space-y-6">
                <div className="relative rounded-3xl overflow-hidden shadow-2xl h-64 group ring-4 ring-white">
                    <img src={selectedActivity.imageUrl} className="w-full h-full object-cover transform transition-transform duration-[2s] group-hover:scale-110" alt={selectedActivity.title} />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-slate-900/40 to-transparent"></div>

                    <div className="absolute bottom-0 left-0 w-full p-6 text-white">
                        <div className="flex flex-wrap items-center gap-3 text-sm font-bold mb-3 opacity-90">
                            {/* Editable Start Time */}
                            <div className="flex items-center bg-white/20 backdrop-blur-md rounded-lg px-3 py-1.5 border border-white/20 shadow-lg hover:bg-white/30 transition-colors">
                                <Clock className="w-4 h-4 mr-2 text-accent" />
                                <input 
                                    type="time" 
                                    className="bg-transparent border-none p-0 text-white font-bold focus:ring-0 w-24 cursor-pointer text-lg tracking-wide outline-none placeholder-white"
                                    value={selectedActivity.startTime}
                                    onChange={(e) => handleDetailsUpdate('startTime', e.target.value)}
                                />
                            </div>

                            {/* Editable Duration */}
                            <div className="flex items-center bg-white/20 backdrop-blur-md rounded-lg px-3 py-1.5 border border-white/20 shadow-lg hover:bg-white/30 transition-colors relative">
                                <Timer className="w-4 h-4 mr-2 text-secondary" />
                                <select 
                                    className="bg-transparent border-none p-0 text-white font-bold focus:ring-0 cursor-pointer text-sm outline-none appearance-none pr-4"
                                    value={selectedActivity.durationMinutes}
                                    onChange={(e) => handleDetailsUpdate('durationMinutes', e.target.value)}
                                >
                                    {[30, 45, 60, 90, 120, 150, 180, 240, 300].map(min => (
                                        <option key={min} value={min} className="text-slate-800">{min < 60 ? `${min} 分鐘` : `${min / 60} 小時`}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <h2 className="text-4xl font-black tracking-tight leading-none mb-2 drop-shadow-lg">{selectedActivity.title}</h2>
                        <div className="flex items-center gap-2 text-sm text-white/80 font-medium">
                            <MapPin className="w-4 h-4" /> {selectedActivity.location}
                        </div>
                    </div>

                    <div className="absolute top-4 right-4 bg-black/20 backdrop-blur-md p-2 rounded-2xl cursor-pointer hover:bg-black/40 transition-colors border border-white/20 shadow-xl"
                         onClick={(e) => toggleStar(e, selectedActivity.id, selectedActivity.rating)}>
                         {[1,2,3,4,5].map(star => (
                             <Star key={star} className={`w-6 h-6 inline-block transition-all hover:scale-110 ${star <= selectedActivity.rating ? 'fill-accent text-accent drop-shadow-[0_0_10px_rgba(250,204,21,0.5)]' : 'text-white/30'}`} />
                         ))}
                    </div>
                </div>

                <div className="space-y-4 px-2">
                    <p className="text-slate-600 text-lg leading-relaxed font-medium first-letter:text-3xl first-letter:font-black first-letter:text-primary first-letter:mr-1">
                        {selectedActivity.description}
                    </p>

                    <div className="grid grid-cols-1 gap-4 mt-4">

                         <div className="bg-gradient-to-br from-yellow-50 to-white p-5 rounded-2xl border border-yellow-100 relative overflow-hidden shadow-sm group hover:shadow-md transition-all">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-yellow-400/10 rounded-full blur-2xl -mr-10 -mt-10"></div>
                            <h5 className="font-bold text-yellow-700 text-sm mb-2 flex items-center gap-2 relative z-10">
                                <span className="bg-yellow-100 p-1 rounded-md"><Star className="w-4 h-4 fill-yellow-600" /></span>
                                推介原因
                            </h5>
                            <p className="text-slate-700 text-sm italic font-medium relative z-10 pl-8 border-l-2 border-yellow-200">
                                “{selectedActivity.reason}”
                            </p>
                         </div>

                        {(selectedActivity.tips || selectedActivity.transportInfo) && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {selectedActivity.tips && (
                                    <div className="bg-orange-50/80 p-5 rounded-2xl border border-orange-100 shadow-sm">
                                        <h5 className="font-bold text-orange-700 text-sm mb-2 flex items-center gap-2">
                                            <Info className="w-4 h-4" /> 注意事項
                                        </h5>
                                        <p className="text-slate-600 text-xs leading-relaxed font-medium">{selectedActivity.tips}</p>
                                    </div>
                                )}
                                {selectedActivity.transportInfo && (
                                    <div className="bg-blue-50/80 p-5 rounded-2xl border border-blue-100 shadow-sm">
                                        <h5 className="font-bold text-blue-700 text-sm mb-2 flex items-center gap-2">
                                            <Navigation className="w-4 h-4" /> 交通建議
                                        </h5>
                                        <p className="text-slate-600 text-xs leading-relaxed font-medium">{selectedActivity.transportInfo}</p>
                                    </div>
                                )}
                            </div>
                        )}

                        <div className="flex justify-center pt-2">
                             <a 
                                href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selectedActivity.title + " " + selectedActivity.location)}`} 
                                target="_blank" 
                                rel="noreferrer"
                                className="inline-flex items-center gap-2 text-sm font-bold text-slate-400 hover:text-primary transition-colors hover:underline"
                             >
                                <ExternalLink className="w-4 h-4" /> 在 Google Maps 查看
                             </a>
                        </div>
                    </div>
                </div>
            </div>
        )}
      </Modal>
    </div>
  );
};

function differenceInDays(start: string, end: string) {
    if(!start || !end) return 1;
    const d1 = new Date(start);
    const d2 = new Date(end);
    return Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24)) + 1;
}

function addMinutes(time: string, minutes: number): string {
    const [h, m] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m + minutes);
    return format(date, 'HH:mm');
}

