                        {(selectedActivity.tips || selectedActivity.transportInfo) && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {selectedActivity.tips && (
                                    <div className="bg-orange-50/80 p-5 rounded-2xl border border-orange-100 shadow-sm">
                                        <h5 className="font-bold text-orange-700 text-sm mb-2 flex items-center gap-2">
                                            <Info className="w-4 h-4" /> 注意事項
                                        </h5>
                                        <p className="text-slate-600 text-xs leading-relaxed font-medium">{selectedActivity.tips}</p>
                                    </div>
                                )}
                                {selectedActivity.transportInfo && (
                                    <div className="bg-blue-50/80 p-5 rounded-2xl border border-blue-100 shadow-sm">
                                        <h5 className="font-bold text-blue-700 text-sm mb-2 flex items-center gap-2">
                                            <Navigation className="w-4 h-4" /> 交通建議
                                        </h5>
                                        <p className="text-slate-600 text-xs leading-relaxed font-medium">{selectedActivity.transportInfo}</p>
                                    </div>
                                )}
                            </div>
                        )}

                        <div className="flex justify-center pt-2">
                             <a 
                                href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selectedActivity.title + " " + selectedActivity.location)}`} 
                                target="_blank" 
                                rel="noreferrer"
                                className="inline-flex items-center gap-2 text-sm font-bold text-slate-400 hover:text-primary transition-colors hover:underline"
                             >
                                <ExternalLink className="w-4 h-4" /> 在 Google Maps 查看
                             </a>
                        </div>
                    </div>
                </div>
            </div>
        )}
      </Modal>
    </div>
  );
};

function differenceInDays(start: string, end: string) {
    if(!start || !end) return 1;
    const d1 = new Date(start);
    const d2 = new Date(end);
    return Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24)) + 1;
}

function addMinutes(time: string, minutes: number): string {
    const [h, m] = time.split(':').map(Number);
    const date = new Date();
    date.setHours(h, m + minutes);
    return format(date, 'HH:mm');
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripData, Activity, Itinerary } from "../types";
import { v4 as uuidv4 } from 'uuid';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// --- DIRECT AI IMAGE GENERATION ---
// Using Pollinations.ai to generate relevant images on the fly based on the prompt.
// This ensures every single activity has a unique, relevant image without "broken" links.

const getImageUrl = (title: string, type: string, destination: string) => {
  const cleanTitle = title.trim();
  const cleanDest = destination.trim();

  // Construct a specific prompt for the AI model
  // We ask for a "travel photography" style to maintain consistency
  const prompt = `travel photography of ${cleanTitle} in ${cleanDest}, ${type} context, cinematic lighting, 4k, highly detailed, realistic, sunny day`;

  const encodedPrompt = encodeURIComponent(prompt);

  // Use a hash of the title as a seed to ensure the image remains constant across re-renders
  // Adding 'nologo=true' to keep it clean
  const seed = Math.abs(hashCode(title));

  // Using 'flux' model if available for better realism, or default
  return `https://image.pollinations.ai/prompt/${encodedPrompt}?width=800&height=600&nologo=true&seed=${seed}&model=flux`;
};

// Simple hash function for deterministic seed
function hashCode(str: string) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return hash;
}

// --- Schemas ---

const activitySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    startTime: { type: Type.STRING, description: "Start time in HH:MM format (24h)" },
    durationMinutes: { type: Type.INTEGER, description: "Duration in minutes" },
    title: { type: Type.STRING },
    description: { type: Type.STRING, description: "Short description of the activity" },
    location: { type: Type.STRING, description: "Address or Place Name" },
    type: { type: Type.STRING, enum: ["food", "sight", "shopping", "transport", "other"] },
    tips: { type: Type.STRING, description: "Important tips or warnings" },
    transportInfo: { type: Type.STRING, description: "How to get there from previous location or accommodation" },
    reason: { type: Type.STRING, description: "Why this was recommended based on user preferences" },
  },
  required: ["startTime", "durationMinutes", "title", "description", "location", "type", "transportInfo"],
};

const daySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    dayIndex: { type: Type.INTEGER },
    activities: {
      type: Type.ARRAY,
      items: activitySchema,
    },
  },
  required: ["dayIndex", "activities"],
};

const itinerarySchema: Schema = {
  type: Type.ARRAY,
  items: daySchema,
};


export const generateInitialItinerary = async (tripData: TripData): Promise<Itinerary> => {
  const ai = getAiClient();

  const daysCount = calculateDays(tripData.arrivalDate, tripData.departureDate);

  const prompt = `
    為前往 ${tripData.destination} 的旅行創建一個詳細的行程表。
    請全部使用繁體中文 (Traditional Chinese) 回覆。

    背景資料:
    - 到埗: ${tripData.arrivalDate} ${tripData.arrivalTime}
    - 回程: ${tripData.departureDate} ${tripData.departureTime}
    - 人數: ${tripData.adults} 大人, ${tripData.children} 小童
    - 主要住宿: ${tripData.accommodation}
    - 早餐時間: ${tripData.breakfastTime}
    - 自駕遊: ${tripData.selfDrive ? "是" : "否"}
    - 旅遊風格: ${tripData.styles.join(", ")}
    - 必去景點: ${tripData.mustSees}

    要求:
    - 計劃 ${daysCount} 天的行程。
    - 第一天在到埗時間後開始，最後一天在回程時間前結束。
    - 每天包括早餐、午餐和晚餐建議（除非在飛機上）。
    - 每天行程在早餐時間後 30 分鐘開始。
    - 考慮住宿地點的交通邏輯，盡量減少路程時間。
    - 每個活動必須有中文名稱及簡介。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        systemInstruction: "你是一位專業的繁體中文旅遊策劃師。請只返回 JSON 格式。",
      },
    });

    const rawData = JSON.parse(response.text || "[]");
    return parseGeminiResponseToItinerary(rawData, tripData.destination);

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

export const regenerateActivity = async (
  tripData: TripData, 
  currentActivity: Activity, 
  dayActivities: Activity[],
  promptOverride?: string
): Promise<Activity> => {
  const ai = getAiClient();

  const prompt = `
    為前往 ${tripData.destination} 的行程重新生成一個活動。
    請使用繁體中文。
    要替換的現有活動: ${currentActivity.title} (${currentActivity.startTime})。

    當天其他活動: ${dayActivities.map(a => `${a.startTime}: ${a.title}`).join(", ")}。
    當天住宿: ${tripData.dailyAccommodations[currentActivity.dayIndex] || tripData.accommodation}。

    ${promptOverride ? `用戶特別要求: ${promptOverride}` : "建議: 提供一個符合時間段和地點流向的替代方案。不要重複現有的活動。"}

    只返回一個活動物件 (JSON)。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: activitySchema,
    },
  });

  const rawActivity = JSON.parse(response.text || "{}");
  return {
    ...currentActivity,
    ...rawActivity,
    id: uuidv4(),
    rating: 0,
    imageUrl: getImageUrl(rawActivity.title || currentActivity.title, rawActivity.type || 'other', tripData.destination),
  };
};

export const regenerateDay = async (
  tripData: TripData,
  dayIndex: number,
  currentActivities: Activity[]
): Promise<Activity[]> => {
  const ai = getAiClient();

  const lockedActivities = currentActivities.filter(a => a.rating === 5);

  const prompt = `
    重新生成 ${tripData.destination} 第 ${dayIndex + 1} 天的行程。
    請使用繁體中文。
    住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
    早餐: ${tripData.breakfastTime}。

    限制:
    - 必須保留這些已鎖定(5星)的活動於指定時間: ${JSON.stringify(lockedActivities.map(a => ({ time: a.startTime, title: a.title })))}。
    - 圍繞這些活動填補當天的其餘時間。
    - 確保流程順暢。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: daySchema,
    },
  });

  const rawData = JSON.parse(response.text || "{}");

  const newActivities = (rawData.activities || []).map((raw: any) => ({
    id: uuidv4(),
    dayIndex: dayIndex,
    startTime: raw.startTime,
    durationMinutes: raw.durationMinutes,
    title: raw.title,
    description: raw.description,
    location: raw.location,
    type: raw.type,
    rating: 0,
    tips: raw.tips,
    transportInfo: raw.transportInfo,
    reason: raw.reason,
    imageUrl: getImageUrl(raw.title, raw.type, tripData.destination),
  }));

  let merged = [...newActivities];
  lockedActivities.forEach(locked => {
    merged = merged.filter(a => a.startTime !== locked.startTime);
    merged.push(locked);
  });

  return merged.sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const suggestGapActivity = async (
  tripData: TripData,
  dayIndex: number,
  startTime: string,
  availableMinutes: number
): Promise<Activity> => {
    const ai = getAiClient();
    const prompt = `
        建議一個行程空檔的短暫活動。
        地點: ${tripData.destination}。
        第 ${dayIndex + 1} 天。
        開始時間: ${startTime}。
        可用時間: ${availableMinutes} 分鐘。
        住宿: ${tripData.dailyAccommodations[dayIndex] || tripData.accommodation}。
        風格: ${tripData.styles.join(', ')}。
        限制: 必須在時間/地點上可行。例如 "Coffee break", "短暫散步", "便利店", "逛小店"。
        請使用繁體中文。
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: activitySchema,
        }
    });

    const raw = JSON.parse(response.text || "{}");
    return {
        id: uuidv4(),
        dayIndex,
        startTime: raw.startTime || startTime, 
        durationMinutes: Math.min(raw.durationMinutes, availableMinutes),
        title: raw.title,
        description: raw.description,
        location: raw.location,
        type: raw.type,
        rating: 0,
        tips: raw.tips,
        transportInfo: raw.transportInfo,
        reason: raw.reason,
        imageUrl: getImageUrl(raw.title, raw.type, tripData.destination),
    };
}


// Utilities

function calculateDays(start: string, end: string) {
  if (!start || !end) return 1;
  const d1 = new Date(start);
  const d2 = new Date(end);
  const diffTime = Math.abs(d2.getTime() - d1.getTime());
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 
}

function parseGeminiResponseToItinerary(data: any[], destination: string): Itinerary {
  const itinerary: Itinerary = [];

  data.forEach((day: any) => {
    if (day.activities && Array.isArray(day.activities)) {
      day.activities.forEach((act: any) => {
        itinerary.push({
          id: uuidv4(),
          dayIndex: day.dayIndex !== undefined ? day.dayIndex - 1 : 0, 
          startTime: act.startTime,
          durationMinutes: act.durationMinutes,
          title: act.title,
          description: act.description,
          location: act.location,
          type: act.type,
          rating: 0,
          tips: act.tips,
          transportInfo: act.transportInfo,
          reason: act.reason,
          imageUrl: getImageUrl(act.title, act.type, destination),
        });
      });
    }
  });

  return itinerary;
}

import React, { useState } from 'react';
import { TripData, Itinerary, Activity } from '../types';
import { Button } from '../components/Button';
import { Modal } from '../components/Modal';
import { MapPin, Clock, Star, RefreshCw, X, Plus, Home, Trash2, GripVertical, ExternalLink, Navigation, Edit, Info, Timer, ImageOff } from 'lucide-react';
