const getSmartImageUrl = (title: string, type: string, destination: string) => {
  const combinedText = `${title} ${destination} ${type}`.toLowerCase();

  // 1. Exact/Partial Keyword Matching
  for (const [key, ids] of Object.entries(UNSPLASH_MAP)) {
    if (combinedText.includes(key)) {
      const index = Math.abs(hashCode(title)) % ids.length;
      return `https://images.unsplash.com/photo-${ids[index]}?auto=format&fit=crop&w=600&q=80`;
    }
  }

  // 2. Type-based Matching (if no specific keyword)
  const typeMap: Record<string, string[]> = {
    'food': UNSPLASH_MAP.ramen,
    'sight': UNSPLASH_MAP.temple,
    'shopping': UNSPLASH_MAP.shopping,
    'transport': UNSPLASH_MAP.train,
  };

  if (typeMap[type]) {
    const ids = typeMap[type];
    const index = Math.abs(hashCode(title)) % ids.length;
    return `https://images.unsplash.com/photo-${ids[index]}?auto=format&fit=crop&w=600&q=80`;
  }

  // 3. Fallback
  const fallbackIndex = Math.abs(hashCode(title)) % GENERAL_FALLBACKS.length;
  return `https://images.unsplash.com/photo-${GENERAL_FALLBACKS[fallbackIndex]}?auto=format&fit=crop&w=600&q=80`;
};

// --- GEMINI IMAGE GENERATION (On Demand) ---
